var QUESTIONS_THEORY_3 = [
{type:"mcq",diff:"easy",en:{q:"What is the primary function of an Operating System?",opts:["To play media files","To manage computer hardware and software resources","To protect from physical damage","To design graphics"],ans:1,exp:"An Operating System (OS) is essential system software that manages computer hardware, software resources, and provides common services for computer programs. It acts as an intermediary between users and computer hardware, ensuring efficient resource allocation and execution of applications."},hi:{q:"ऑपरेटिंग सिस्टम का प्राथमिक कार्य क्या है?",opts:["मीडिया फ़ाइलें चलाने के लिए","कंप्यूटर हार्डवेयर और सॉफ्टवेयर संसाधनों का प्रबंधन करने के लिए","शारीरिक क्षति से बचाने के लिए","ग्राफिक्स डिजाइन करने के लिए"],ans:1,exp:"ऑपरेटिंग सिस्टम (OS) एक आवश्यक सिस्टम सॉफ्टवेयर है जो कंप्यूटर हार्डवेयर, सॉफ्टवेयर संसाधनों का प्रबंधन करता है और प्रोग्राम के लिए सामान्य सेवाएं प्रदान करता है। यह उपयोगकर्ता और हार्डवेयर के बीच एक मध्यस्थ के रूप में कार्य करता है, जिससे कुशल संसाधन आवंटन होता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does GUI stand for in the context of Windows Operating System?",opts:["Graphical User Interface","Graphical Universal Interface","General User Interaction","General Utility Interface"],ans:0,exp:"GUI stands for Graphical User Interface. It allows users to interact with electronic devices through graphical icons and audio indicator such as primary notation, instead of text-based UIs, typed command labels or text navigation. Windows is a classic example of a GUI OS."},hi:{q:"विंडोज ऑपरेटिंग सिस्टम के संदर्भ में GUI का क्या अर्थ है?",opts:["ग्राफिकल यूजर इंटरफेस","ग्राफिकल यूनिवर्सल इंटरफेस","जनरल यूजर इंटरेक्शन","जनरल यूटिलिटी इंटरफेस"],ans:0,exp:"GUI का अर्थ ग्राफिकल यूजर इंटरफेस है। यह उपयोगकर्ताओं को टेक्स्ट-आधारित UI या टाइप किए गए कमांड के बजाय ग्राफिकल आइकन और दृश्य संकेतकों के माध्यम से इलेक्ट्रॉनिक उपकरणों के साथ बातचीत करने की अनुमति देता है। विंडोज एक क्लासिक GUI OS है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following is the main screen area that you see after turning on your computer and logging into Windows?",opts:["Taskbar","Control Panel","Desktop","Start Menu"],ans:2,exp:"The Desktop is the primary user interface of a computer. When you boot up a computer and log in, the desktop is the first screen you see. It serves as a surface for your work, containing icons for files, folders, and applications."},hi:{q:"कंप्यूटर चालू करने और विंडोज में लॉग इन करने के बाद आप जो मुख्य स्क्रीन क्षेत्र देखते हैं, वह कौन सा है?",opts:["टास्कबार","कंट्रोल पैनल","डेस्कटॉप","स्टार्ट मेन्यू"],ans:2,exp:"डेस्कटॉप कंप्यूटर का प्राथमिक यूजर इंटरफेस है। जब आप कंप्यूटर बूट करते हैं और लॉग इन करते हैं, तो डेस्कटॉप वह पहली स्क्रीन होती है जिसे आप देखते हैं। यह आपके काम के लिए एक सतह के रूप में कार्य करता है, जिसमें फ़ाइलों और एप्लिकेशन के आइकन होते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Where is the Taskbar typically located on the Windows desktop by default?",opts:["Top of the screen","Left side of the screen","Right side of the screen","Bottom of the screen"],ans:3,exp:"By default, the Windows Taskbar is located at the bottom of the screen. It allows you to locate and launch programs through Start and the Start menu, or view any program that's currently open. It can be moved to other edges if customized."},hi:{q:"डिफ़ॉल्ट रूप से विंडोज डेस्कटॉप पर टास्कबार आमतौर पर कहाँ स्थित होता है?",opts:["स्क्रीन के शीर्ष पर","स्क्रीन के बाईं ओर","स्क्रीन के दाईं ओर","स्क्रीन के नीचे"],ans:3,exp:"डिफ़ॉल्ट रूप से, विंडोज टास्कबार स्क्रीन के नीचे स्थित होता है। यह आपको स्टार्ट मेन्यू के माध्यम से प्रोग्राम खोजने और लॉन्च करने या वर्तमान में खुले किसी भी प्रोग्राम को देखने की अनुमति देता है। इसे अन्य किनारों पर भी ले जाया जा सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which icon provides access to a central hierarchical database of all files and folders on your computer?",opts:["Recycle Bin","This PC / My Computer","Network","Control Panel"],ans:1,exp:"'This PC' (formerly 'My Computer') provides a graphical interface to view and manage all the disk drives, files, and folders on your system. It acts as the root navigation point for local storage devices and connected peripheral drives."},hi:{q:"कौन सा आइकन आपके कंप्यूटर पर सभी फ़ाइलों और फ़ोल्डरों के केंद्रीय पदानुक्रमित डेटाबेस तक पहुंच प्रदान करता है?",opts:["रिसाइकिल बिन","दिस पीसी / माई कंप्यूटर","नेटवर्क","कंट्रोल पैनल"],ans:1,exp:"'दिस पीसी' (पूर्व में 'माई कंप्यूटर') आपके सिस्टम पर सभी डिस्क ड्राइव, फ़ाइलों और फ़ोल्डरों को देखने और प्रबंधित करने के लिए एक ग्राफिकल इंटरफ़ेस प्रदान करता है। यह स्थानीय स्टोरेज डिवाइस के लिए रूट नेविगेशन बिंदु के रूप में कार्य करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Where do deleted files and folders temporarily go before they are permanently removed?",opts:["System Tray","Recycle Bin","Control Panel","Downloads Folder"],ans:1,exp:"The Recycle Bin acts as a holding area for deleted files and folders. Items remain here until the bin is emptied, allowing users to restore mistakenly deleted data. Once emptied, the space is marked as free for the operating system to overwrite."},hi:{q:"स्थायी रूप से हटाए जाने से पहले हटाई गई फ़ाइलें और फ़ोल्डर अस्थायी रूप से कहाँ जाते हैं?",opts:["सिस्टम ट्रे","रिसाइकिल बिन","कंट्रोल पैनल","डाउनलोड फ़ोल्डर"],ans:1,exp:"रिसाइकिल बिन हटाई गई फ़ाइलों और फ़ोल्डरों के लिए एक होल्डिंग क्षेत्र के रूप में कार्य करता है। आइटम यहाँ तब तक रहते हैं जब तक बिन खाली नहीं हो जाता, जिससे उपयोगकर्ता डेटा को पुनर्स्थापित कर सकते हैं। खाली होने के बाद, डेटा स्थायी रूप से मिट जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is a temporary storage area in Windows where cut or copied text and images are stored?",opts:["Clipboard","Notepad","Hard Drive","RAM Disk"],ans:0,exp:"The Clipboard is a special location in your computer's memory (RAM) that temporarily stores data that has been cut or copied. This allows the data to be pasted into a different location or application. It is overwritten with each new copy command."},hi:{q:"विंडोज में वह अस्थायी संग्रहण क्षेत्र क्या है जहाँ कट या कॉपी किए गए टेक्स्ट और चित्र संग्रहीत होते हैं?",opts:["क्लिपबोर्ड","नोटपैड","हार्ड ड्राइव","रैम डिस्क"],ans:0,exp:"क्लिपबोर्ड आपके कंप्यूटर की मेमोरी (RAM) में एक विशेष स्थान है जो अस्थायी रूप से उस डेटा को संग्रहीत करता है जिसे कट या कॉपी किया गया है। यह डेटा को एक अलग स्थान पर पेस्ट करने की अनुमति देता है। हर नए कॉपी कमांड के साथ यह बदल जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the standard file extension for a plain text file created in Notepad?",opts:[".docx",".txt",".pdf",".rtf"],ans:1,exp:"The .txt extension denotes a plain text file. It contains only raw text without any formatting such as bold, italics, or specific fonts. Notepad is the default application in Windows for creating and editing these lightweight text files."},hi:{q:"नोटपैड में बनाई गई एक सादे पाठ (plain text) फ़ाइल के लिए मानक फ़ाइल एक्सटेंशन क्या है?",opts:[".docx",".txt",".pdf",".rtf"],ans:1,exp:".txt एक्सटेंशन एक सादे टेक्स्ट फ़ाइल को दर्शाता है। इसमें बोल्ड, इटैलिक या विशिष्ट फोंट जैसे किसी भी स्वरूपण के बिना केवल कच्चा पाठ होता है। नोटपैड विंडोज में इन फ़ाइलों को बनाने और संपादित करने के लिए डिफ़ॉल्ट एप्लिकेशन है।"}},
{type:"mcq",diff:"easy",en:{q:"Which file extension typically indicates an executable program file in Windows?",opts:[".exe",".sys",".dll",".ini"],ans:0,exp:"The .exe extension stands for 'executable'. It is the standard file format used by Windows to run programs and software. When a user double-clicks an .exe file, the OS executes the compiled machine code contained within it."},hi:{q:"विंडोज में कौन सा फ़ाइल एक्सटेंशन आमतौर पर निष्पादन योग्य (executable) प्रोग्राम फ़ाइल को इंगित करता है?",opts:[".exe",".sys",".dll",".ini"],ans:0,exp:".exe एक्सटेंशन का अर्थ 'निष्पादन योग्य' (executable) है। यह प्रोग्राम और सॉफ्टवेयर चलाने के लिए विंडोज द्वारा उपयोग किया जाने वाला मानक फ़ाइल स्वरूप है। जब कोई उपयोगकर्ता .exe फ़ाइल पर डबल-क्लिक करता है, तो OS इसके अंदर के कोड को निष्पादित करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the keyboard shortcut to COPY selected items in Windows?",opts:["Ctrl + X","Ctrl + V","Ctrl + C","Ctrl + Z"],ans:2,exp:"Ctrl + C is the universal keyboard shortcut in Windows to copy selected text, files, or objects to the clipboard. Unlike the 'Cut' command, copying leaves the original item intact in its source location."},hi:{q:"विंडोज में चयनित आइटम को COPY करने के लिए कीबोर्ड शॉर्टकट क्या है?",opts:["Ctrl + X","Ctrl + V","Ctrl + C","Ctrl + Z"],ans:2,exp:"Ctrl + C क्लिपबोर्ड पर चयनित टेक्स्ट, फ़ाइलों या ऑब्जेक्ट्स को कॉपी करने के लिए विंडोज में सार्वभौमिक कीबोर्ड शॉर्टकट है। 'कट' कमांड के विपरीत, कॉपी करने से मूल आइटम अपने स्रोत स्थान पर बरकरार रहता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the keyboard shortcut to PASTE items from the clipboard?",opts:["Ctrl + P","Ctrl + V","Ctrl + X","Ctrl + S"],ans:1,exp:"Ctrl + V is used to paste the contents currently stored in the clipboard to the active cursor location or selected folder. The 'V' stands in visually for an insertion mark or 'Velcro', as 'P' is reserved for printing."},hi:{q:"क्लिपबोर्ड से आइटम PASTE करने के लिए कीबोर्ड शॉर्टकट क्या है?",opts:["Ctrl + P","Ctrl + V","Ctrl + X","Ctrl + S"],ans:1,exp:"Ctrl + V का उपयोग क्लिपबोर्ड में वर्तमान में संग्रहीत सामग्री को सक्रिय कर्सर स्थान या चयनित फ़ोल्डर में पेस्ट करने के लिए किया जाता है। 'P' शॉर्टकट प्रिंटिंग के लिए आरक्षित है, इसलिए पेस्ट के लिए 'V' का उपयोग होता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which shortcut key combination is used to UNDO the last action performed?",opts:["Ctrl + Y","Ctrl + Z","Ctrl + U","Ctrl + A"],ans:1,exp:"Ctrl + Z is the standard shortcut command to Undo an action. It reverts the state of a document or file system back to exactly how it was before the last change was made, preventing accidental data loss or deletion."},hi:{q:"किए गए अंतिम कार्य को पूर्ववत (UNDO) करने के लिए किस शॉर्टकट कुंजी संयोजन का उपयोग किया जाता है?",opts:["Ctrl + Y","Ctrl + Z","Ctrl + U","Ctrl + A"],ans:1,exp:"Ctrl + Z किसी क्रिया को पूर्ववत (Undo) करने के लिए मानक शॉर्टकट कमांड है। यह किसी दस्तावेज़ या फ़ाइल सिस्टम की स्थिति को बिल्कुल वैसा ही कर देता है जैसा अंतिम परिवर्तन किए जाने से पहले था, जिससे आकस्मिक डेटा हानि को रोका जा सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"How can you quickly switch between multiple open application windows in Windows?",opts:["Alt + Tab","Ctrl + Tab","Shift + Tab","Windows + Tab"],ans:0,exp:"Alt + Tab is a powerful task switcher shortcut. Holding Alt and tapping Tab displays an overlay of all open windows, allowing the user to rapidly cycle through and bring a specific background application to the foreground."},hi:{q:"विंडोज में कई खुले एप्लिकेशन विंडो के बीच आप जल्दी से कैसे स्विच कर सकते हैं?",opts:["Alt + Tab","Ctrl + Tab","Shift + Tab","Windows + Tab"],ans:0,exp:"Alt + Tab एक शक्तिशाली टास्क स्विचर शॉर्टकट है। Alt को पकड़कर और Tab को टैप करने से सभी खुली विंडो का ओवरले प्रदर्शित होता है, जिससे उपयोगकर्ता तेज़ी से नेविगेट कर सकता है और किसी एप्लिकेशन को सामने ला सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the purpose of the 'Title Bar' in a Windows application?",opts:["To show the current file size","To display the application name and file name","To navigate through folders","To provide formatting tools"],ans:1,exp:"The Title Bar is the horizontal strip at the very top of an application window. It universally displays the name of the software currently being used and the title of the active document, along with window control buttons (minimize, maximize, close)."},hi:{q:"विंडोज एप्लिकेशन में 'टाइटल बार' का उद्देश्य क्या है?",opts:["वर्तमान फ़ाइल आकार दिखाने के लिए","एप्लिकेशन का नाम और फ़ाइल का नाम प्रदर्शित करने के लिए","फ़ोल्डरों के माध्यम से नेविगेट करने के लिए","स्वरूपण उपकरण प्रदान करने के लिए"],ans:1,exp:"टाइटल बार एक एप्लिकेशन विंडो के सबसे ऊपर क्षैतिज पट्टी है। यह सार्वभौमिक रूप से उपयोग किए जा रहे सॉफ़्टवेयर का नाम और सक्रिय दस्तावेज़ का शीर्षक प्रदर्शित करता है, साथ ही विंडो नियंत्रण बटन (न्यूनीकृत, अधिकतम, बंद) भी दिखाता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which part of a window allows you to move the visible content up, down, left, or right when it exceeds the window size?",opts:["Menu bar","Status bar","Scroll bar","Taskbar"],ans:2,exp:"A Scroll bar appears at the right and/or bottom edges of a window when the content is too large to fit entirely within the visible pane. Clicking and dragging the scroll box or arrows shifts the visible area of the document."},hi:{q:"विंडो का कौन सा हिस्सा आपको दृश्य सामग्री को ऊपर, नीचे, बाएं या दाएं ले जाने की अनुमति देता है जब यह विंडो के आकार से अधिक हो जाता है?",opts:["मेन्यू बार","स्टेटस बार","स्क्रॉल बार","टास्कबार"],ans:2,exp:"जब सामग्री पूरी तरह से दिखाई देने वाले फलक (pane) के भीतर फिट होने के लिए बहुत बड़ी होती है, तो विंडो के दाएं और/या निचले किनारे पर एक स्क्रॉल बार दिखाई देता है। इसे खींचने से दस्तावेज़ का दृश्य क्षेत्र बदल जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What does the 'Minimize' button do to an open window?",opts:["Closes the application completely","Shrinks the window to an icon on the Taskbar","Makes the window fill the entire screen","Restores the window to its previous size"],ans:1,exp:"Clicking the Minimize button (typically represented by a minus sign '-') hides the application window from the desktop and suspends it as a background task. The application remains running and can be restored by clicking its icon on the Taskbar."},hi:{q:"एक खुली विंडो पर 'मिनिमाइज़' (Minimize) बटन क्या करता है?",opts:["एप्लिकेशन को पूरी तरह से बंद कर देता है","विंडो को टास्कबार पर एक आइकन में सिकोड़ देता है","विंडो को पूरी स्क्रीन पर भर देता है","विंडो को उसके पिछले आकार में पुनर्स्थापित करता है"],ans:1,exp:"मिनिमाइज़ बटन (आमतौर पर ऋण चिह्न '-' द्वारा दर्शाया गया) पर क्लिक करने से डेस्कटॉप से ​​एप्लिकेशन विंडो छिप जाती है और इसे पृष्ठभूमि कार्य के रूप में निलंबित कर दिया जाता है। इसे टास्कबार पर इसके आइकन पर क्लिक करके पुनर्स्थापित किया जा सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the default background image or pattern on the Windows Desktop called?",opts:["Screen saver","Wallpaper","Theme","Icon"],ans:1,exp:"The desktop background, commonly referred to as the Wallpaper, is the digital image (photo, drawing, etc.) used as a decorative background of a graphical user interface on the screen of a computer. It is highly customizable by the user."},hi:{q:"विंडोज डेस्कटॉप पर डिफ़ॉल्ट बैकग्राउंड छवि या पैटर्न को क्या कहा जाता है?",opts:["स्क्रीन सेवर","वॉलपेपर","थीम","आइकन"],ans:1,exp:"डेस्कटॉप बैकग्राउंड, जिसे आमतौर पर वॉलपेपर कहा जाता है, एक डिजिटल छवि है जिसका उपयोग कंप्यूटर की स्क्रीन पर ग्राफिकल यूजर इंटरफेस की सजावटी पृष्ठभूमि के रूप में किया जाता है। इसे उपयोगकर्ता द्वारा अनुकूलित (customize) किया जा सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is a 'Screen Saver'?",opts:["A tool to reduce screen brightness","An animation that appears when the computer is idle","A program to save deleted files","A virus protection mechanism"],ans:1,exp:"A Screen Saver is a computer program that blanks the screen or fills it with moving images or patterns when the computer has been idle for a designated time. Originally designed to prevent phosphor burn-in on CRT monitors, it is now mostly used for security and aesthetics."},hi:{q:"'स्क्रीन सेवर' (Screen Saver) क्या है?",opts:["स्क्रीन की चमक कम करने का एक उपकरण","एक एनीमेशन जो कंप्यूटर के निष्क्रिय होने पर दिखाई देता है","हटाए गए फ़ाइलों को सहेजने के लिए एक प्रोग्राम","एक वायरस सुरक्षा तंत्र"],ans:1,exp:"स्क्रीन सेवर एक कंप्यूटर प्रोग्राम है जो निर्दिष्ट समय के लिए कंप्यूटर के निष्क्रिय रहने पर स्क्रीन को खाली कर देता है या इसे चलती छवियों से भर देता है। मूल रूप से CRT मॉनिटर पर बर्न-इन को रोकने के लिए डिज़ाइन किया गया था, अब इसका उपयोग सौंदर्य के लिए होता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which mouse action is typically used to open a file or launch an application?",opts:["Single click","Right click","Double click","Drag and drop"],ans:2,exp:"A Double-click involves pressing the primary mouse button (usually the left button) twice quickly in succession without moving the mouse. In Windows, this action is universally mapped to executing an application or opening a file/folder."},hi:{q:"किसी फ़ाइल को खोलने या एप्लिकेशन लॉन्च करने के लिए आमतौर पर किस माउस क्रिया का उपयोग किया जाता है?",opts:["सिंगल क्लिक","राइट क्लिक","डबल क्लिक","ड्रैग एंड ड्रॉप"],ans:2,exp:"डबल-क्लिक में माउस को हिलाए बिना प्राथमिक माउस बटन (आमतौर पर बायां बटन) को लगातार दो बार जल्दी दबाना शामिल है। विंडोज में, इस क्रिया का उपयोग एप्लिकेशन को निष्पादित करने या फ़ाइल/फ़ोल्डर खोलने के लिए किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What happens when you 'Right-click' on a file or folder in Windows?",opts:["It opens the file","It deletes the file","It opens a context menu with options","It renames the file"],ans:2,exp:"Right-clicking an object in Windows triggers a Context Menu. This dynamic menu presents a list of commands and options (like copy, paste, delete, properties) that are directly applicable to the specific item that was clicked."},hi:{q:"विंडोज में किसी फ़ाइल या फ़ोल्डर पर 'राइट-क्लिक' करने पर क्या होता है?",opts:["यह फ़ाइल खोलता है","यह फ़ाइल को हटा देता है","यह विकल्पों के साथ एक संदर्भ मेनू (context menu) खोलता है","यह फ़ाइल का नाम बदल देता है"],ans:2,exp:"विंडोज में किसी ऑब्जेक्ट पर राइट-क्लिक करने से कॉन्टेक्स्ट मेनू (Context Menu) ट्रिगर होता है। यह डायनेमिक मेनू कमांड और विकल्पों (जैसे कॉपी, पेस्ट, डिलीट, प्रॉपर्टीज़) की एक सूची प्रस्तुत करता है जो सीधे उस आइटम पर लागू होते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What is the process of moving an item on the screen by holding down the mouse button called?",opts:["Clicking","Hovering","Drag and drop","Scrolling"],ans:2,exp:"Drag and Drop is a pointing device gesture in which the user selects a virtual object by 'grabbing' it (pressing and holding the mouse button) and dragging it to a different location or onto another object to perform a move or copy operation."},hi:{q:"माउस बटन को दबाए रखकर स्क्रीन पर किसी आइटम को ले जाने की प्रक्रिया को क्या कहा जाता है?",opts:["क्लिक करना","होवर करना","ड्रैग एंड ड्रॉप","स्क्रॉल करना"],ans:2,exp:"ड्रैग एंड ड्रॉप (Drag and Drop) एक जेस्चर है जिसमें उपयोगकर्ता किसी आभासी ऑब्जेक्ट को 'पकड़कर' (माउस बटन को दबाकर और पकड़कर) और मूव या कॉपी ऑपरेशन करने के लिए इसे किसी भिन्न स्थान पर खींचकर ले जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the standard Windows accessory used for basic drawing and image editing?",opts:["Notepad","WordPad","MS Paint","Calculator"],ans:2,exp:"MS Paint (Microsoft Paint) is a simple raster graphics editor that has been included with all versions of Microsoft Windows. It allows users to draw basic shapes, add text, and perform simple image editing tasks like cropping and resizing."},hi:{q:"बुनियादी ड्राइंग और छवि संपादन के लिए उपयोग किया जाने वाला मानक विंडोज एक्सेसरी क्या है?",opts:["नोटपैड","वर्डपैड","एमएस पेंट (MS Paint)","कैलकुलेटर"],ans:2,exp:"MS Paint एक साधारण रास्टर ग्राफिक्स एडिटर है जिसे Microsoft Windows के सभी संस्करणों के साथ शामिल किया गया है। यह उपयोगकर्ताओं को बुनियादी आकृतियाँ बनाने, पाठ जोड़ने और क्रॉपिंग जैसे सरल छवि संपादन कार्य करने की अनुमति देता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the process of restarting a computer that is already powered on called?",opts:["Cold Boot","Warm Boot","Hard Reset","Shutdown"],ans:1,exp:"A Warm Boot (or soft boot) is the process of restarting a computer that is already turned on and running, typically initiated via the operating system's restart command. It clears the RAM without physically cutting power to the hardware components."},hi:{q:"पहले से चालू कंप्यूटर को फिर से शुरू (Restart) करने की प्रक्रिया को क्या कहा जाता है?",opts:["कोल्ड बूट","वार्म बूट (Warm Boot)","हार्ड रीसेट","शटडाउन"],ans:1,exp:"एक वार्म बूट (Warm Boot) पहले से चालू और चल रहे कंप्यूटर को पुनरारंभ करने की प्रक्रिया है, जो आमतौर पर ऑपरेटिंग सिस्टम के रिस्टार्ट कमांड के माध्यम से शुरू की जाती है। यह हार्डवेयर घटकों की बिजली काटे बिना RAM को साफ करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which of the following describes a 'Folder' in Windows?",opts:["A software program","A digital container used to store files and other folders","A type of computer virus","A hardware component"],ans:1,exp:"A Folder, also known as a directory, is a logical container used within a file system to organize and store files and other nested sub-folders. It helps in maintaining a structured and manageable hierarchy of data on storage drives."},hi:{q:"विंडोज में 'फ़ोल्डर' (Folder) का सही वर्णन क्या है?",opts:["एक सॉफ्टवेयर प्रोग्राम","फ़ाइलों और अन्य फ़ोल्डरों को संग्रहीत करने के लिए उपयोग किया जाने वाला एक डिजिटल कंटेनर","एक प्रकार का कंप्यूटर वायरस","एक हार्डवेयर घटक"],ans:1,exp:"एक फ़ोल्डर, जिसे निर्देशिका (directory) भी कहा जाता है, एक तार्किक कंटेनर है जिसका उपयोग फ़ाइल सिस्टम के भीतर फ़ाइलों और अन्य उप-फ़ोल्डरों को व्यवस्थित और संग्रहीत करने के लिए किया जाता है। यह डेटा का पदानुक्रम बनाए रखने में मदद करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is a small, informative text box that appears when you hover the mouse pointer over an icon or button?",opts:["Dialog box","Command prompt","Tooltip","Start menu"],ans:2,exp:"A Tooltip is a common graphical user interface element. When a user hovers the pointer over an item without clicking, a small hover box appears presenting supplementary information regarding the item being hovered over, explaining its function."},hi:{q:"एक छोटा, सूचनात्मक टेक्स्ट बॉक्स क्या है जो तब दिखाई देता है जब आप माउस पॉइंटर को किसी आइकन या बटन पर होवर (रखते) करते हैं?",opts:["डायलॉग बॉक्स","कमांड प्रॉम्प्ट","टूलटिप (Tooltip)","स्टार्ट मेन्यू"],ans:2,exp:"टूलटिप (Tooltip) एक सामान्य ग्राफिकल यूजर इंटरफेस तत्व है। जब कोई उपयोगकर्ता बिना क्लिक किए पॉइंटर को किसी आइटम पर घुमाता है, तो एक छोटा बॉक्स दिखाई देता है जो उस आइटम के बारे में अतिरिक्त जानकारी प्रस्तुत करता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the primary difference between WordPad and Notepad?",opts:["Notepad is for images; WordPad is for text","WordPad supports text formatting (bold, colors); Notepad does not","WordPad is a web browser; Notepad is a text editor","There is no difference"],ans:1,exp:"Notepad is a basic text editor strictly for plain text (.txt) with no formatting capability. WordPad is a more advanced word processor that supports Rich Text Format (.rtf), allowing users to add colors, bold, italics, and insert images."},hi:{q:"वर्डपैड (WordPad) और नोटपैड (Notepad) के बीच प्राथमिक अंतर क्या है?",opts:["नोटपैड छवियों के लिए है; वर्डपैड पाठ के लिए है","वर्डपैड टेक्स्ट स्वरूपण (बोल्ड, रंग) का समर्थन करता है; नोटपैड नहीं करता है","वर्डपैड एक वेब ब्राउज़र है; नोटपैड एक टेक्स्ट एडिटर है","कोई अंतर नहीं है"],ans:1,exp:"नोटपैड बिना किसी स्वरूपण क्षमता वाले सादे पाठ (.txt) के लिए एक बुनियादी टेक्स्ट एडिटर है। वर्डपैड एक अधिक उन्नत वर्ड प्रोसेसर है जो रिच टेक्स्ट फॉर्मेट (.rtf) का समर्थन करता है, जिससे उपयोगकर्ता रंग, बोल्ड और चित्र जोड़ सकते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which standard application in Windows is used for performing mathematical calculations?",opts:["Excel","Calculator","MathPad","Word"],ans:1,exp:"The Windows Calculator is a software-based calculation tool included in all versions of Windows. It features a standard mode for basic arithmetic and an advanced scientific mode for complex algebraic, trigonometric, and statistical computations."},hi:{q:"गणितीय गणना करने के लिए विंडोज में किस मानक एप्लिकेशन का उपयोग किया जाता है?",opts:["एक्सेल (Excel)","कैलकुलेटर (Calculator)","मैथपैड (MathPad)","वर्ड (Word)"],ans:1,exp:"विंडोज कैलकुलेटर विंडोज के सभी संस्करणों में शामिल एक सॉफ्टवेयर-आधारित गणना उपकरण है। इसमें बुनियादी अंकगणित के लिए एक मानक मोड और जटिल बीजीय, त्रिकोणमितीय गणनाओं के लिए एक उन्नत वैज्ञानिक मोड है।"}},
{type:"mcq",diff:"easy",en:{q:"Where can a user typically find the system clock indicating the current Date and Time in Windows?",opts:["On the Desktop background","In the middle of the Taskbar","In the System Tray (Notification Area)","Inside My Computer"],ans:2,exp:"The system clock is traditionally located in the System Tray (also known as the Notification Area) on the far right side of the default Taskbar. Clicking it expands a calendar widget and allows access to date/time settings."},hi:{q:"विंडोज में उपयोगकर्ता आमतौर पर वर्तमान दिनांक और समय दर्शाने वाली सिस्टम घड़ी कहाँ पा सकता है?",opts:["डेस्कटॉप बैकग्राउंड पर","टास्कबार के मध्य में","सिस्टम ट्रे (अधिसूचना क्षेत्र) में","माई कंप्यूटर के अंदर"],ans:2,exp:"सिस्टम घड़ी पारंपरिक रूप से डिफ़ॉल्ट टास्कबार के दाईं ओर सिस्टम ट्रे (जिसे अधिसूचना क्षेत्र भी कहा जाता है) में स्थित होती है। इस पर क्लिक करने से एक कैलेंडर विजेट फैलता है और दिनांक/समय सेटिंग्स तक पहुंच मिलती है।"}},
{type:"tf",diff:"easy",en:{q:"Windows is an open-source operating system, meaning anyone can freely modify its core source code.",opts:["True","False"],ans:1,exp:"Windows is a proprietary, closed-source operating system developed and owned entirely by Microsoft Corporation. Its source code is not publicly available or legally modifiable by standard end-users, unlike open-source OSs like Linux."},hi:{q:"विंडोज एक ओपन-सोर्स ऑपरेटिंग सिस्टम है, जिसका अर्थ है कि कोई भी इसके कोर सोर्स कोड को स्वतंत्र रूप से संशोधित कर सकता है।",opts:["सही","गलत"],ans:1,exp:"विंडोज एक मालिकाना, क्लोज-सोर्स ऑपरेटिंग सिस्टम है जिसे माइक्रोसॉफ्ट कॉर्पोरेशन द्वारा विकसित और प्रबंधित किया गया है। लिनक्स जैसे ओपन-सोर्स OS के विपरीत, इसका सोर्स कोड सार्वजनिक रूप से उपलब्ध नहीं है।"}},
{type:"tf",diff:"easy",en:{q:"Items moved to the Recycle Bin can be restored to their original locations before the bin is emptied.",opts:["True","False"],ans:0,exp:"The Recycle Bin acts as a fail-safe. When a user deletes a file, it is merely moved to the Recycle Bin directory. The user can easily select 'Restore' on the item to return it to its exact original path before deletion."},hi:{q:"रिसाइकिल बिन में ले जाए गए आइटम को बिन खाली होने से पहले उनके मूल स्थानों पर पुनर्स्थापित (restore) किया जा सकता है।",opts:["सही","गलत"],ans:0,exp:"रिसाइकिल बिन एक फेल-सेफ के रूप में कार्य करता है। जब कोई उपयोगकर्ता किसी फ़ाइल को हटाता है, तो उसे रिसाइकिल बिन में ले जाया जाता है। उपयोगकर्ता हटाने से पहले इसे उसके मूल पथ पर वापस करने के लिए 'पुनर्स्थापित करें' (Restore) का चयन कर सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"What does NTFS stand for in the context of Windows file systems?",opts:["Network Table File System","New Technology File System","National Technical File System","Non-Transferable File System"],ans:1,exp:"NTFS stands for New Technology File System. Introduced with Windows NT, it is the primary and modern file system for Windows, offering significant improvements over FAT32 in terms of security, performance, reliability, and support for massive file sizes."},hi:{q:"विंडोज फ़ाइल सिस्टम के संदर्भ में NTFS का क्या अर्थ है?",opts:["नेटवर्क टेबल फ़ाइल सिस्टम","न्यू टेक्नोलॉजी फ़ाइल सिस्टम (New Technology File System)","नेशनल टेक्निकल फ़ाइल सिस्टम","नॉन-ट्रांसफरेबल फ़ाइल सिस्टम"],ans:1,exp:"NTFS का अर्थ न्यू टेक्नोलॉजी फ़ाइल सिस्टम है। विंडोज NT के साथ पेश किया गया, यह सुरक्षा, प्रदर्शन, विश्वसनीयता और बड़े फ़ाइल आकारों के समर्थन के मामले में FAT32 पर महत्वपूर्ण सुधार की पेशकश करने वाला प्राथमिक फ़ाइल सिस्टम है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the absolute maximum individual file size allowed on a FAT32 formatted USB drive?",opts:["2 GB","4 GB","8 GB","16 GB"],ans:1,exp:"The FAT32 (File Allocation Table 32) file system has a hard architectural limitation where no single file can exceed 4 Gigabytes (minus 1 byte) in size. Attempting to copy a larger file will result in an error, necessitating a format to NTFS or exFAT."},hi:{q:"FAT32 स्वरूपित USB ड्राइव पर अनुमत पूर्ण अधिकतम व्यक्तिगत फ़ाइल आकार (file size) क्या है?",opts:["2 GB","4 GB","8 GB","16 GB"],ans:1,exp:"FAT32 फ़ाइल सिस्टम की एक सीमा है जहाँ कोई भी एकल फ़ाइल आकार में 4 गीगाबाइट (माइनस 1 बाइट) से अधिक नहीं हो सकती है। एक बड़ी फ़ाइल की प्रतिलिपि बनाने का प्रयास करने पर एक त्रुटि होगी, जिसके लिए NTFS में स्वरूपित (format) करने की आवश्यकता होगी।"}},
{type:"mcq",diff:"medium",en:{q:"Which Windows System Tool securely completely wipes all data from a disk drive and prepares it for a new file system?",opts:["Disk Cleanup","Disk Defragmenter","Format","System Restore"],ans:2,exp:"The Format utility completely erases all existing address tables and data on a storage drive, establishing a blank new file system (like NTFS or FAT32). It is a destructive process essential for preparing fresh drives or repairing deeply corrupted ones."},hi:{q:"कौन सा विंडोज सिस्टम टूल डिस्क ड्राइव से सभी डेटा को पूरी तरह से मिटा देता है और इसे नए फ़ाइल सिस्टम के लिए तैयार करता है?",opts:["डिस्क क्लीनअप","डिस्क डीफ्रैग्मेंटर","फॉर्मेट (Format)","सिस्टम रीस्टोर"],ans:2,exp:"प्रारूप (Format) उपयोगिता भंडारण ड्राइव पर सभी मौजूदा डेटा को पूरी तरह से मिटा देती है, जिससे एक खाली नया फ़ाइल सिस्टम (जैसे NTFS या FAT32) स्थापित होता है। यह ताजा ड्राइव तैयार करने के लिए आवश्यक एक विनाशकारी प्रक्रिया है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the primary purpose of the 'Disk Cleanup' utility in Windows?",opts:["To scan for computer viruses","To free up disk space by removing unnecessary temporary files","To repair damaged hardware sectors","To backup important user data"],ans:1,exp:"Disk Cleanup is a maintenance utility designed to free up storage space on a hard drive. It searches and safely deletes obsolete files, such as downloaded program files, temporary internet files, Windows error reports, and files residing in the Recycle Bin."},hi:{q:"विंडोज में 'डिस्क क्लीनअप' (Disk Cleanup) उपयोगिता का प्राथमिक उद्देश्य क्या है?",opts:["कंप्यूटर वायरस के लिए स्कैन करना","अनावश्यक अस्थायी फ़ाइलों को हटाकर डिस्क स्थान खाली करना","क्षतिग्रस्त हार्डवेयर क्षेत्रों की मरम्मत करना","महत्वपूर्ण उपयोगकर्ता डेटा का बैकअप लेना"],ans:1,exp:"डिस्क क्लीनअप एक रखरखाव उपयोगिता है जिसे हार्ड ड्राइव पर स्टोरेज स्पेस खाली करने के लिए डिज़ाइन किया गया है। यह अस्थायी इंटरनेट फ़ाइलों और रिसाइकिल बिन में रहने वाली फ़ाइलों को सुरक्षित रूप से हटा देता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which utility physically reorganizes fragmented data blocks on a mechanical hard drive to improve read/write speed?",opts:["Disk Cleanup","Disk Defragmenter","Task Manager","System Restore"],ans:1,exp:"Disk Defragmenter consolidates fragmented files stored across disparate physical locations on a spinning hard drive. By organizing data blocks into contiguous physical sectors, the drive's read/write head movement is minimized, significantly improving overall access speeds."},hi:{q:"कौन सी उपयोगिता रीड/राइट गति में सुधार करने के लिए मैकेनिकल हार्ड ड्राइव पर खंडित (fragmented) डेटा ब्लॉकों को भौतिक रूप से पुनर्गठित करती है?",opts:["डिस्क क्लीनअप","डिस्क डीफ्रैग्मेंटर (Disk Defragmenter)","टास्क मैनेजर","सिस्टम रीस्टोर"],ans:1,exp:"डिस्क डीफ्रैग्मेंटर हार्ड ड्राइव पर अलग-अलग भौतिक स्थानों पर संग्रहीत खंडित फ़ाइलों को समेकित (इकट्ठा) करता है। डेटा ब्लॉकों को निरंतर भौतिक क्षेत्रों में व्यवस्थित करके, यह समग्र पहुँच गति (access speed) में काफी सुधार करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What feature enables users to revert their computer's state (including system files and registry) to a previous point in time?",opts:["System Backup","System Restore","Safe Mode","Disk Check"],ans:1,exp:"System Restore is a recovery feature that takes 'snapshots' of system files, installed applications, and the Windows Registry at specific intervals (Restore Points). If Windows becomes unstable, rolling back to a previous point can resolve severe software-induced issues without affecting personal documents."},hi:{q:"कौन सी सुविधा उपयोगकर्ताओं को अपने कंप्यूटर की स्थिति (सिस्टम फ़ाइलों और रजिस्ट्री सहित) को समय के पिछले बिंदु पर वापस लाने में सक्षम बनाती है?",opts:["सिस्टम बैकअप","सिस्टम रीस्टोर (System Restore)","सेफ मोड","डिस्क चेक"],ans:1,exp:"सिस्टम रिस्टोर एक रिकवरी सुविधा है जो विशिष्ट अंतराल पर सिस्टम फाइलों और विंडोज रजिस्ट्री का 'स्नैपशॉट' (पुनर्स्थापना बिंदु) लेती है। यदि विंडोज अस्थिर हो जाता है, तो पिछले बिंदु पर वापस जाने से गंभीर सॉफ़्टवेयर समस्याओं का समाधान हो सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"Historically, which function key is repeatedly pressed during boot to access the 'Advanced Boot Options' menu (Safe Mode) in Windows 7?",opts:["F2","F8","F12","F10"],ans:1,exp:"In legacy Windows versions like Windows 7, rapidly pressing the F8 key immediately after the BIOS POST screen interrupts the standard boot process, launching the Advanced Boot Options menu. This menu allows users to select troubleshooting environments like Safe Mode."},hi:{q:"विंडोज 7 में 'एडवांस्ड बूट ऑप्शंस' मेनू (सेफ मोड) तक पहुंचने के लिए बूट के दौरान ऐतिहासिक रूप से कौन सी फ़ंक्शन कुंजी बार-बार दबाई जाती है?",opts:["F2","F8","F12","F10"],ans:1,exp:"विंडोज 7 जैसे पुराने विंडोज संस्करणों में, BIOS POST स्क्रीन के तुरंत बाद F8 कुंजी को तेजी से दबाने से मानक बूट प्रक्रिया बाधित हो जाती है और उन्नत बूट विकल्प मेनू लॉन्च हो जाता है। यह उपयोगकर्ताओं को सेफ मोड (Safe Mode) का चयन करने की अनुमति देता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which keyboard shortcut forcefully opens the Windows Task Manager directly?",opts:["Ctrl + Alt + Del","Ctrl + Shift + Esc","Alt + F4","Windows + T"],ans:1,exp:"While Ctrl+Alt+Del brings up a security screen where Task Manager can be selected, pressing Ctrl + Shift + Esc instantly and directly launches the Task Manager, bypassing the intermediary security screen. It is highly useful for rapidly terminating frozen applications."},hi:{q:"कौन सा कीबोर्ड शॉर्टकट सीधे विंडोज टास्क मैनेजर को खोलता है?",opts:["Ctrl + Alt + Del","Ctrl + Shift + Esc","Alt + F4","Windows + T"],ans:1,exp:"जबकि Ctrl+Alt+Del एक सुरक्षा स्क्रीन लाता है जहां टास्क मैनेजर का चयन किया जा सकता है, Ctrl + Shift + Esc दबाने से तुरंत और सीधे टास्क मैनेजर लॉन्च होता है। जमे हुए (frozen) एप्लिकेशन को तेजी से समाप्त करने के लिए यह अत्यधिक उपयोगी है।"}},
{type:"mcq",diff:"medium",en:{q:"Which specialized Control Panel applet is utilized to update hardware drivers and troubleshoot malfunctioning physical components?",opts:["Programs and Features","Network and Sharing Center","Device Manager","System Configuration"],ans:2,exp:"The Device Manager provides a graphical view of the hardware attached to a computer. It is explicitly used to manage hardware, enable/disable devices, troubleshoot conflicts, and install or update the software drivers required for hardware to communicate with Windows."},hi:{q:"हार्डवेयर ड्राइवरों को अपडेट करने और भौतिक घटकों के समस्या निवारण के लिए किस विशेष कंट्रोल पैनल एप्लेट का उपयोग किया जाता है?",opts:["प्रोग्राम्स एंड फीचर्स","नेटवर्क एंड शेयरिंग सेंटर","डिवाइस मैनेजर (Device Manager)","सिस्टम कॉन्फ़िगरेशन"],ans:2,exp:"डिवाइस मैनेजर कंप्यूटर से जुड़े हार्डवेयर का एक ग्राफिकल दृश्य प्रदान करता है। इसका उपयोग स्पष्ट रूप से हार्डवेयर को प्रबंधित करने, उपकरणों को सक्षम/अक्षम करने और हार्डवेयर के लिए आवश्यक सॉफ़्टवेयर ड्राइवरों को स्थापित या अद्यतन करने के लिए किया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What does UAC stand for, a security feature that prompts for permission before making administrative changes?",opts:["Universal Access Control","User Account Control","Unified Administrator Command","User Authorization Center"],ans:1,exp:"User Account Control (UAC) is a vital security component in Windows. It mitigates the impact of malware by requiring administrators to explicitly approve privilege elevation requests. It forces all applications to run with standard user privileges until authorization is granted."},hi:{q:"UAC का क्या अर्थ है, एक सुरक्षा सुविधा जो प्रशासनिक परिवर्तन करने से पहले अनुमति मांगती है?",opts:["यूनिवर्सल एक्सेस कंट्रोल","यूजर अकाउंट कंट्रोल (User Account Control)","यूनिफाइड एडमिनिस्ट्रेटर कमांड","यूजर ऑथराइजेशन सेंटर"],ans:1,exp:"यूजर अकाउंट कंट्रोल (UAC) विंडोज में एक महत्वपूर्ण सुरक्षा घटक है। यह विशेषाधिकार अनुरोधों को स्पष्ट रूप से अनुमोदित करने की आवश्यकता से मैलवेयर के प्रभाव को कम करता है। प्राधिकरण दिए जाने तक यह सभी एप्लिकेशन को मानक उपयोगकर्ता विशेषाधिकारों के साथ चलाने के लिए मजबूर करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is a primary restriction of a 'Standard User' account compared to an 'Administrator' account?",opts:["Cannot use the internet","Cannot install global software or change critical system settings","Cannot change their own desktop wallpaper","Cannot use Microsoft Word"],ans:1,exp:"A Standard User account can utilize most installed software and change personal settings (like wallpaper). However, it is restricted from making system-wide changes, such as installing new software, modifying the registry, or changing security protocols, which require an Administrator."},hi:{q:"'प्रशासक' (Administrator) खाते की तुलना में 'मानक उपयोगकर्ता' (Standard User) खाते का प्राथमिक प्रतिबंध क्या है?",opts:["इंटरनेट का उपयोग नहीं कर सकते","वैश्विक सॉफ़्टवेयर स्थापित नहीं कर सकता या महत्वपूर्ण सिस्टम सेटिंग्स को नहीं बदल सकता","अपना स्वयं का डेस्कटॉप वॉलपेपर नहीं बदल सकता","माइक्रोसॉफ्ट वर्ड का उपयोग नहीं कर सकते"],ans:1,exp:"एक मानक उपयोगकर्ता (Standard User) खाता अधिकांश स्थापित सॉफ़्टवेयर का उपयोग कर सकता है और व्यक्तिगत सेटिंग्स बदल सकता है। हालाँकि, इसे सिस्टम-व्यापी परिवर्तन करने से प्रतिबंधित किया गया है, जैसे कि नए सॉफ़्टवेयर स्थापित करना या सुरक्षा प्रोटोकॉल बदलना।"}},
{type:"mcq",diff:"medium",en:{q:"How can a user reveal system files that are intentionally concealed by the operating system?",opts:["By renaming the files","By changing the View settings in Folder Options","By using the Task Manager","By restarting in Safe Mode"],ans:1,exp:"Windows hides critical system files by default to prevent accidental modification or deletion. To view them, a user must open 'Folder Options' (or File Explorer Options), navigate to the 'View' tab, and explicitly select the radio button 'Show hidden files, folders, and drives'."},hi:{q:"कोई उपयोगकर्ता उन सिस्टम फ़ाइलों को कैसे प्रकट कर सकता है जिन्हें ऑपरेटिंग सिस्टम द्वारा जानबूझकर छुपाया गया है?",opts:["फ़ाइलों का नाम बदलकर","फ़ोल्डर विकल्पों में 'व्यू' (View) सेटिंग्स को बदलकर","टास्क मैनेजर का उपयोग करके","सेफ मोड में पुनरारंभ करके"],ans:1,exp:"विंडोज डिफ़ॉल्ट रूप से महत्वपूर्ण सिस्टम फ़ाइलों को छुपाता है ताकि आकस्मिक संशोधन को रोका जा सके। उन्हें देखने के लिए, उपयोगकर्ता को 'फ़ोल्डर विकल्प' (Folder Options) खोलना होगा, 'व्यू' टैब पर जाना होगा, और 'छुपी हुई फाइलें दिखाएं' का चयन करना होगा।"}},
{type:"mcq",diff:"medium",en:{q:"What action does pressing the 'Print Screen' (PrtScn) key perform in Windows?",opts:["Sends the current document directly to the printer","Captures an image of the entire screen and copies it to the clipboard","Closes the active window instantly","Opens the Screen Resolution settings"],ans:1,exp:"Pressing the Print Screen key takes a graphical snapshot of the entire visible screen exactly as it currently appears and quietly saves this image raster data directly to the Windows Clipboard, where it can then be pasted into programs like Paint or Word."},hi:{q:"विंडोज में 'प्रिंट स्क्रीन' (PrtScn) कुंजी दबाने पर कौन सी क्रिया होती है?",opts:["वर्तमान दस्तावेज़ को सीधे प्रिंटर पर भेजता है","पूरी स्क्रीन की एक छवि कैप्चर करता है और इसे क्लिपबोर्ड पर कॉपी करता है","सक्रिय विंडो को तुरंत बंद कर देता है","स्क्रीन रिज़ॉल्यूशन सेटिंग्स खोलता है"],ans:1,exp:"प्रिंट स्क्रीन (PrtScn) कुंजी दबाने से पूरी दिखाई देने वाली स्क्रीन का स्नैपशॉट कैप्चर हो जाता है और इस छवि को सीधे विंडोज क्लिपबोर्ड में कॉपी कर दिया जाता है, जहां से इसे पेंट या वर्ड जैसे कार्यक्रमों में पेस्ट किया जा सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which built-in Windows utility allows users to easily capture highly specific, customizable rectangular or free-form screenshots?",opts:["Paint 3D","Notepad","Snipping Tool / Snip & Sketch","Calculator"],ans:2,exp:"The Snipping Tool (modernized as Snip & Sketch) is an advanced screenshot utility. Unlike the crude Print Screen key, it allows users to meticulously select specific rectangular areas, individual windows, or free-form shapes to capture and annotate digitally."},hi:{q:"कौन सी इन-बिल्ट विंडोज उपयोगिता उपयोगकर्ताओं को आसानी से विशिष्ट, अनुकूलन योग्य आयताकार या फ्री-फॉर्म स्क्रीनशॉट कैप्चर करने की अनुमति देती है?",opts:["पेंट 3डी (Paint 3D)","नोटपैड","स्निपिंग टूल (Snipping Tool) / स्निप एंड स्केच","कैलकुलेटर"],ans:2,exp:"स्निपिंग टूल एक उन्नत स्क्रीनशॉट उपयोगिता है। प्रिंट स्क्रीन कुंजी के विपरीत, यह उपयोगकर्ताओं को कैप्चर करने और एनोटेट करने के लिए विशिष्ट आयताकार क्षेत्रों, व्यक्तिगत विंडो या फ्री-फॉर्म आकृतियों को सावधानीपूर्वक चुनने की अनुमति देता है।"}},
{type:"mcq",diff:"medium",en:{q:"Setting a file's attribute to 'Read-only' enforces what restriction?",opts:["The file can only be opened by an Administrator","The file can be opened and read, but its contents cannot be altered or saved over","The file is hidden from standard directory searches","The file is encrypted with a password"],ans:1,exp:"When the 'Read-only' attribute is applied to a file via its Properties dialog, the operating system locks the file against modification. Users can open and view the data, but if they attempt to save changes, they will be forced to save it as a new, separate file."},hi:{q:"किसी फ़ाइल के गुण (attribute) को 'रीड-ओनली' (Read-only) पर सेट करने से कौन सा प्रतिबंध लागू होता है?",opts:["फ़ाइल को केवल व्यवस्थापक द्वारा खोला जा सकता है","फ़ाइल को खोला और पढ़ा जा सकता है, लेकिन इसकी सामग्री को बदला या सहेजा नहीं जा सकता है","फ़ाइल मानक निर्देशिका खोजों से छिपी हुई है","फ़ाइल एक पासवर्ड के साथ एन्क्रिप्टेड है"],ans:1,exp:"जब किसी फ़ाइल पर 'रीड-ओनली' विशेषता लागू की जाती है, तो ओएस फ़ाइल को संशोधन के खिलाफ लॉक कर देता है। उपयोगकर्ता डेटा खोल और देख सकते हैं, लेकिन यदि वे परिवर्तन सहेजने का प्रयास करते हैं, तो उन्हें इसे एक नई, अलग फ़ाइल के रूप में सहेजना होगा।"}},
{type:"mcq",diff:"medium",en:{q:"Which accessory tool is used to insert special typographical symbols and letters not physically present on a standard keyboard?",opts:["On-Screen Keyboard","Notepad","Character Map","WordPad"],ans:2,exp:"The Character Map is a utility used to view the characters available in a selected font and copy specific, obscure symbols (like copyright ©, trademark ™, or foreign accents) to the clipboard for insertion into documents."},hi:{q:"मानक कीबोर्ड पर भौतिक रूप से मौजूद नहीं होने वाले विशेष टाइपोग्राफ़िकल प्रतीकों और अक्षरों को सम्मिलित करने के लिए किस एक्सेसरी टूल का उपयोग किया जाता है?",opts:["ऑन-स्क्रीन कीबोर्ड","नोटपैड","कैरेक्टर मैप (Character Map)","वर्डपैड"],ans:2,exp:"कैरेक्टर मैप एक उपयोगिता है जिसका उपयोग चयनित फ़ॉन्ट में उपलब्ध वर्णों को देखने और विशिष्ट प्रतीकों (जैसे कॉपीराइट ©, ट्रेडमार्क ™) को दस्तावेजों में शामिल करने के लिए क्लिपबोर्ड पर कॉपी करने के लिए किया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is 'Virtual Memory' in the Windows operating system architecture?",opts:["RAM located on the graphics card","A hidden partition reserved for backups","A file on the hard drive (Pagefile.sys) used by the OS as an extension of physical RAM","Memory stored in the cloud (OneDrive)"],ans:2,exp:"Virtual Memory is an intricate memory management technique. When physical RAM is exhausted, Windows utilizes a hidden file on the hard drive (Pagefile.sys) as simulated RAM. It temporarily swaps inactive memory pages to the disk to free up high-speed RAM for active tasks."},hi:{q:"विंडोज ऑपरेटिंग सिस्टम वास्तुकला में 'वर्चुअल मेमोरी' क्या है?",opts:["ग्राफिक्स कार्ड पर स्थित रैम (RAM)","बैकअप के लिए आरक्षित एक छिपा हुआ विभाजन","ओएस द्वारा भौतिक रैम के विस्तार के रूप में उपयोग की जाने वाली हार्ड ड्राइव पर एक फ़ाइल (Pagefile.sys)","क्लाउड में संग्रहीत मेमोरी (OneDrive)"],ans:2,exp:"वर्चुअल मेमोरी एक जटिल मेमोरी प्रबंधन तकनीक है। जब भौतिक रैम समाप्त हो जाती है, तो विंडोज हार्ड ड्राइव पर एक छिपी हुई फ़ाइल (Pagefile.sys) का उपयोग नकली रैम के रूप में करता है। यह उच्च गति रैम को मुक्त करने के लिए डिस्क पर निष्क्रिय मेमोरी को स्वैप करता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the primary technical difference between 'Sleep' mode and 'Hibernate' mode?",opts:["Sleep turns off the PC entirely; Hibernate keeps fans running","Sleep saves state to RAM and uses low power; Hibernate saves state to the Hard Drive and uses zero power","Sleep saves to Hard Drive; Hibernate saves to RAM","There is no physical difference"],ans:1,exp:"Sleep mode maintains the current session entirely in the volatile RAM, requiring a constant trickle of power to keep data alive for instant wake up. Hibernate writes the entire RAM contents to a non-volatile file on the hard disk (hiberfil.sys) and powers off completely, consuming zero energy."},hi:{q:"'स्लीप' (Sleep) मोड और 'हाइबरनेट' (Hibernate) मोड के बीच प्राथमिक तकनीकी अंतर क्या है?",opts:["स्लीप पीसी को पूरी तरह से बंद कर देता है; हाइबरनेट प्रशंसकों को चालू रखता है","स्लीप अवस्था को रैम में सहेजता है और कम बिजली का उपयोग करता है; हाइबरनेट अवस्था को हार्ड ड्राइव में सहेजता है और शून्य बिजली का उपयोग करता है","स्लीप हार्ड ड्राइव में बचाता है; हाइबरनेट रैम में बचाता है","कोई भौतिक अंतर नहीं है"],ans:1,exp:"स्लीप मोड वर्तमान सत्र को अस्थिर रैम में रखता है, जिससे तत्काल जागने के लिए निरंतर बिजली की आवश्यकता होती है। हाइबरनेट हार्ड डिस्क पर फ़ाइल में संपूर्ण RAM सामग्री लिखता है और पूरी तरह से बंद हो जाता है, जिससे शून्य ऊर्जा की खपत होती है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the integrated anti-malware and antivirus component native to modern Windows 10/11 operating systems?",opts:["Norton AntiVirus","Windows Defender (Windows Security)","McAfee Security","Kaspersky Free"],ans:1,exp:"Windows Defender (now integrated into Windows Security) is Microsoft's robust, built-in anti-malware and antivirus solution. It provides real-time protection, periodic scanning, and cloud-delivered updates against software threats natively, without requiring third-party installations."},hi:{q:"आधुनिक विंडोज 10/11 ऑपरेटिंग सिस्टम का मूल एंटी-मैलवेयर और एंटीवायरस घटक क्या है?",opts:["नॉर्टन एंटीवायरस (Norton AntiVirus)","विंडोज डिफेंडर (Windows Defender / Security)","मैकेफी सुरक्षा (McAfee Security)","कैस्पर्सकी फ्री (Kaspersky Free)"],ans:1,exp:"विंडोज डिफेंडर (अब विंडोज सिक्योरिटी में एकीकृत) माइक्रोसॉफ्ट का इन-बिल्ट एंटी-मैलवेयर और एंटीवायरस समाधान है। यह तृतीय-पक्ष (third-party) इंस्टॉलेशन की आवश्यकता के बिना सॉफ्टवेयर खतरों के खिलाफ वास्तविक समय सुरक्षा और स्कैनिंग प्रदान करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which built-in software specifically monitors and controls incoming and outgoing network traffic based on predetermined security rules?",opts:["Windows Defender","Windows Firewall","System Configuration","Task Scheduler"],ans:1,exp:"The Windows Firewall is a critical network security system. It acts as an electronic barrier, deeply analyzing data packets traveling over the network and actively blocking malicious connections or unauthorized outgoing traffic based on rigid administrative rules."},hi:{q:"कौन सा इन-बिल्ट सॉफ़्टवेयर विशेष रूप से पूर्व निर्धारित सुरक्षा नियमों के आधार पर आने वाले और जाने वाले नेटवर्क ट्रैफ़िक की निगरानी और नियंत्रण करता है?",opts:["विंडोज डिफेंडर","विंडोज फ़ायरवॉल (Windows Firewall)","सिस्टम कॉन्फ़िगरेशन","टास्क शेड्यूलर"],ans:1,exp:"विंडोज फ़ायरवॉल एक महत्वपूर्ण नेटवर्क सुरक्षा प्रणाली है। यह एक इलेक्ट्रॉनिक अवरोध के रूप में कार्य करता है, जो नेटवर्क पर यात्रा करने वाले डेटा पैकेटों का विश्लेषण करता है और दुर्भावनापूर्ण कनेक्शन या अनधिकृत आउटगोइंग ट्रैफ़िक को रोकता है।"}},
{type:"mcq",diff:"medium",en:{q:"Pressing the 'Windows Key + R' combination immediately launches which interface?",opts:["The Registry Editor","The Run dialog box","The Recycle Bin","The Resource Monitor"],ans:1,exp:"The Windows Key + R shortcut is universally mapped to open the 'Run' dialog box. This tiny interface allows advanced users to rapidly launch executable programs, open system folders, or run CLI tools directly by typing their explicit system path or executable name (e.g., 'cmd' or 'calc')."},hi:{q:"'Windows कुंजी + R' संयोजन दबाने से तुरंत कौन सा इंटरफ़ेस लॉन्च होता है?",opts:["रजिस्ट्री संपादक (Registry Editor)","रन डायलॉग बॉक्स (Run dialog box)","रिसाइकिल बिन","संसाधन मॉनिटर (Resource Monitor)"],ans:1,exp:"Windows Key + R शॉर्टकट 'रन' (Run) डायलॉग बॉक्स खोलने के लिए मैप किया गया है। यह इंटरफ़ेस उन्नत उपयोगकर्ताओं को उनका स्पष्ट सिस्टम पथ या निष्पादन योग्य नाम (जैसे, 'cmd' या 'calc') टाइप करके सीधे प्रोग्राम लॉन्च करने की अनुमति देता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which keyboard shortcut instantly opens 'File Explorer' (formerly Windows Explorer)?",opts:["Windows Key + F","Windows Key + E","Ctrl + E","Alt + E"],ans:1,exp:"Pressing Windows Key + E is the universal macro to instantly launch File Explorer. It provides immediate access to the graphical file management system, opening either 'This PC' or 'Quick Access' depending on current OS configuration settings."},hi:{q:"कौन सा कीबोर्ड शॉर्टकट तुरंत 'फ़ाइल एक्सप्लोरर' (पूर्व में विंडोज एक्सप्लोरर) खोलता है?",opts:["Windows Key + F","Windows Key + E","Ctrl + E","Alt + E"],ans:1,exp:"Windows Key + E दबाना फ़ाइल एक्सप्लोरर को तुरंत लॉन्च करने का सार्वभौमिक मैक्रो है। यह ग्राफिकल फ़ाइल प्रबंधन प्रणाली तक तत्काल पहुंच प्रदान करता है, जो वर्तमान OS कॉन्फ़िगरेशन सेटिंग्स के आधार पर 'दिस पीसी' या 'क्विक एक्सेस' खोलता है।"}},
{type:"mcq",diff:"medium",en:{q:"When navigating the Windows file system, what distinguishes an 'Absolute Path' from a 'Relative Path'?",opts:["Absolute paths only work on the internet","Absolute paths contain the full drive letter and directory tree to the file","Relative paths are encrypted","Absolute paths cannot contain spaces"],ans:1,exp:"An Absolute path specifies the exact, complete mathematical location of a file starting directly from the root drive letter (e.g., C:\\Users\\Admin\\Docs\\file.txt). A Relative path describes the file's location only in relation to the current working directory, not the absolute root."},hi:{q:"विंडोज फ़ाइल सिस्टम को नेविगेट करते समय, 'निरपेक्ष पथ' (Absolute Path) को 'सापेक्ष पथ' (Relative Path) से क्या अलग करता है?",opts:["निरपेक्ष पथ केवल इंटरनेट पर काम करते हैं","निरपेक्ष पथ में पूर्ण ड्राइव अक्षर और फ़ाइल की निर्देशिका ट्री शामिल होती है","सापेक्ष पथ एन्क्रिप्टेड हैं","निरपेक्ष पथ में रिक्त स्थान नहीं हो सकते"],ans:1,exp:"एक निरपेक्ष पथ सीधे रूट ड्राइव अक्षर (जैसे, C:\\Users\\Admin\\Docs\\file.txt) से शुरू होने वाली फ़ाइल का सटीक और पूर्ण स्थान निर्दिष्ट करता है। एक सापेक्ष पथ केवल वर्तमान कार्यशील निर्देशिका के संबंध में फ़ाइल के स्थान का वर्णन करता है।"}},
{type:"mcq",diff:"medium",en:{q:"In Windows file searching, what specific function does the asterisk (*) wildcard strictly serve?",opts:["It replaces exactly one single character","It replaces zero or multiple unknown characters in a search string","It forces the search to be case-sensitive","It searches only for hidden system files"],ans:1,exp:"The asterisk (*) is a powerful wildcard character in search queries. It acts as a placeholder for any string of characters (zero or more). For example, searching for '*.doc' will return all files ending with that extension, regardless of the filename length or content."},hi:{q:"विंडोज फ़ाइल खोज में, तारांकन (*) वाइल्डकार्ड विशेष रूप से क्या कार्य करता है?",opts:["यह ठीक एक एकल वर्ण (character) को प्रतिस्थापित करता है","यह खोज स्ट्रिंग में शून्य या एकाधिक अज्ञात वर्णों को प्रतिस्थापित करता है","यह खोज को केस-संवेदी (case-sensitive) होने के लिए बाध्य करता है","यह केवल छिपी हुई सिस्टम फ़ाइलों की खोज करता है"],ans:1,exp:"तारांकन (*) खोज प्रश्नों में एक शक्तिशाली वाइल्डकार्ड वर्ण है। यह वर्णों (शून्य या अधिक) के किसी भी स्ट्रिंग के लिए प्लेसहोल्डर के रूप में कार्य करता है। उदाहरण के लिए, '*.doc' खोजने पर उस एक्सटेंशन के साथ समाप्त होने वाली सभी फाइलें वापस आ जाएंगी।"}},
{type:"mcq",diff:"medium",en:{q:"In Windows command line operations, what does the question mark (?) wildcard signify?",opts:["It represents an entire folder name","It represents exactly one single unknown character","It executes a help command","It searches only for executable files"],ans:1,exp:"Unlike the asterisk (*), the question mark (?) wildcard is highly specific. It strictly replaces exactly one single character in a search string. For example, a search for 'file?.txt' will return 'file1.txt' and 'fileA.txt', but it will completely ignore 'file12.txt'."},hi:{q:"विंडोज कमांड लाइन संचालन में, प्रश्न चिह्न (?) वाइल्डकार्ड क्या दर्शाता है?",opts:["यह एक पूरे फ़ोल्डर नाम का प्रतिनिधित्व करता है","यह ठीक एक एकल अज्ञात वर्ण (character) का प्रतिनिधित्व करता है","यह एक हेल्प कमांड को निष्पादित करता है","यह केवल निष्पादन योग्य फ़ाइलों की खोज करता है"],ans:1,exp:"तारांकन (*) के विपरीत, प्रश्न चिह्न (?) वाइल्डकार्ड अत्यधिक विशिष्ट है। यह खोज स्ट्रिंग में ठीक एक ही वर्ण को सख्ती से प्रतिस्थापित करता है। उदाहरण के लिए, 'file?.txt' की खोज करने पर 'file1.txt' और 'fileA.txt' वापस आएंगे, लेकिन यह 'file12.txt' को अनदेखा कर देगा।"}},
{type:"mcq",diff:"medium",en:{q:"Which built-in command-line tool is used to test the basic network connectivity and latency between your computer and an IP address?",opts:["ipconfig","netstat","ping","tracert"],ans:2,exp:"The 'ping' utility utilizes ICMP echo request packets to verify network connectivity. By sending data packets to a targeted IP address and waiting for a reply, it measures the Round-Trip Time (RTT) and determines if the remote host is physically reachable and responding."},hi:{q:"आपके कंप्यूटर और IP पते के बीच बुनियादी नेटवर्क कनेक्टिविटी और विलंबता (latency) का परीक्षण करने के लिए किस इन-बिल्ट कमांड-लाइन टूल का उपयोग किया जाता है?",opts:["ipconfig","netstat","ping (पिंग)","tracert"],ans:2,exp:"'पिंग' (ping) उपयोगिता नेटवर्क कनेक्टिविटी को सत्यापित करने के लिए ICMP इको रिक्वेस्ट पैकेट का उपयोग करती है। डेटा पैकेट को लक्षित IP पते पर भेजकर और उत्तर की प्रतीक्षा करके, यह मापता है कि दूरस्थ होस्ट भौतिक रूप से पहुंच योग्य है और जवाब दे रहा है या नहीं।"}},
{type:"mcq",diff:"medium",en:{q:"Which specialized tool provides an advanced, graphical, real-time breakdown of CPU, Memory, Disk, and Network utilization beyond standard Task Manager?",opts:["Device Manager","Resource Monitor","Event Viewer","Registry Editor"],ans:1,exp:"The Resource Monitor (resmon.exe) is an advanced diagnostic utility that provides highly granular, real-time data regarding hardware utilization. It breaks down resource usage deeply per individual process, allowing administrators to pinpoint exactly which service is bottlenecking the hard drive or network."},hi:{q:"कौन सा विशेष उपकरण मानक टास्क मैनेजर से परे CPU, मेमोरी, डिस्क और नेटवर्क उपयोग का एक उन्नत, ग्राफिकल और रीयल-टाइम ब्रेकडाउन प्रदान करता है?",opts:["डिवाइस मैनेजर","रिसोर्स मॉनिटर (Resource Monitor)","इवेंट व्यूअर","रजिस्ट्री संपादक"],ans:1,exp:"संसाधन मॉनिटर (Resource Monitor) एक उन्नत नैदानिक ​​उपयोगिता है जो हार्डवेयर उपयोग के संबंध में अत्यधिक दानेदार (granular), रीयल-टाइम डेटा प्रदान करती है। यह व्यक्तिगत प्रक्रिया के अनुसार संसाधन उपयोग को गहराई से तोड़ता है, जिससे व्यवस्थापकों को अड़चन का पता लगाने में मदद मिलती है।"}},
{type:"mcq",diff:"medium",en:{q:"What happens if you drag a file from one folder and drop it into another folder located on a completely DIFFERENT hard drive?",opts:["The file is Copied","The file is Moved","A Shortcut is created","The file is Deleted"],ans:0,exp:"By default Windows file management logic dictates that dragging and dropping a file between directories on the SAME drive initiates a 'Move' operation. However, dragging a file to a directory located on a DIFFERENT physical or logical drive automatically defaults to a 'Copy' operation."},hi:{q:"यदि आप किसी फ़ाइल को एक फ़ोल्डर से खींचकर पूरी तरह से भिन्न हार्ड ड्राइव पर स्थित किसी अन्य फ़ोल्डर में छोड़ देते हैं (ड्रैग एंड ड्रॉप) तो क्या होता है?",opts:["फ़ाइल कॉपी (Copy) हो जाती है","फ़ाइल मूव (Move) हो जाती है","एक शॉर्टकट (Shortcut) बन जाता है","फ़ाइल डिलीट (Delete) हो जाती है"],ans:0,exp:"डिफ़ॉल्ट रूप से विंडोज में, एक ही ड्राइव पर फ़ोल्डरों के बीच किसी फ़ाइल को खींचने और छोड़ने से 'मूव' (Move) ऑपरेशन शुरू होता है। हालाँकि, किसी भिन्न भौतिक या तार्किक ड्राइव पर स्थित निर्देशिका में किसी फ़ाइल को खींचने पर वह डिफ़ॉल्ट रूप से 'कॉपी' (Copy) ऑपरेशन बन जाता है।"}},
{type:"tf",diff:"medium",en:{q:"Formatting a hard disk drive via the Windows GUI immediately and permanently overwrites all previous data with zeroes, making recovery impossible.",opts:["True","False"],ans:1,exp:"A standard Quick Format in Windows does not overwrite the raw data; it merely deletes the Master File Table (MFT) references, marking the space as available. The physical data remains intact and can be recovered with specialized forensics software until actively overwritten."},hi:{q:"विंडोज GUI के माध्यम से हार्ड डिस्क ड्राइव को प्रारूपित (Formatting) करने से सभी पिछले डेटा शून्य (zeroes) के साथ तुरंत और स्थायी रूप से अधिलेखित हो जाते हैं, जिससे रिकवरी असंभव हो जाती है।",opts:["सही","गलत"],ans:1,exp:"विंडोज में एक मानक 'क्विक फॉर्मेट' (Quick Format) कच्चे डेटा को ओवरराइट नहीं करता है; यह केवल मास्टर फाइल टेबल (MFT) संदर्भों को हटा देता है। भौतिक डेटा बरकरार रहता है और सक्रिय रूप से अधिलेखित (overwritten) होने तक विशेष सॉफ़्टवेयर के साथ पुनर्प्राप्त किया जा सकता है।"}},
{type:"tf",diff:"medium",en:{q:"The Windows file system strictly prevents you from creating two files with the exact same name and extension within the exact same folder.",opts:["True","False"],ans:0,exp:"This is true. Windows strictly enforces file naming collisions. In any single directory, file names (including their extensions) must be mathematically unique. If you attempt to save 'document.txt' where one already exists, the OS will prompt you to either overwrite or rename the file."},hi:{q:"विंडोज फ़ाइल सिस्टम आपको एक ही फ़ोल्डर के भीतर एक ही नाम और एक्सटेंशन वाली दो फाइलें बनाने से सख्ती से रोकता है।",opts:["सही","गलत"],ans:0,exp:"यह सत्य है। विंडोज फ़ाइल नामकरण टकरावों को सख्ती से लागू करता है। किसी भी एकल निर्देशिका में, फ़ाइल नाम (उनके एक्सटेंशन सहित) अद्वितीय होने चाहिए। यदि आप समान नाम वाली फ़ाइल सहेजने का प्रयास करते हैं, तो OS आपको ओवरराइट करने या नाम बदलने के लिए प्रेरित करेगा।"}},
{type:"mcq",diff:"hard",en:{q:"During the standard Windows boot sequence, what is the specific name of the critical boot manager file responsible for reading the BCD and loading the OS kernel?",opts:["NTLDR","BOOTMGR","WINLOAD.EXE","NTDETECT.COM"],ans:1,exp:"In modern Windows (Vista and later), BOOTMGR (Windows Boot Manager) replaces the legacy NTLDR. BOOTMGR reads the Boot Configuration Data (BCD) store to display the operating system selection menu and subsequently calls winload.exe to aggressively load the core NT kernel into memory."},hi:{q:"मानक विंडोज बूट अनुक्रम के दौरान, BCD को पढ़ने और OS कर्नेल को लोड करने के लिए जिम्मेदार महत्वपूर्ण बूट मैनेजर फ़ाइल का विशिष्ट नाम क्या है?",opts:["NTLDR","BOOTMGR (बूटएमजीआर)","WINLOAD.EXE","NTDETECT.COM"],ans:1,exp:"आधुनिक विंडोज (विस्टा और बाद में) में, BOOTMGR (विंडोज बूट मैनेजर) पुराने NTLDR की जगह लेता है। BOOTMGR ऑपरेटिंग सिस्टम चयन मेनू प्रदर्शित करने के लिए बूट कॉन्फ़िगरेशन डेटा (BCD) को पढ़ता है और NT कर्नेल को मेमोरी में लोड करने के लिए winload.exe को कॉल करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In the intricate hierarchical structure of the Windows Registry, which primary root key hive securely stores data specific to the physically logged-on user?",opts:["HKEY_LOCAL_MACHINE","HKEY_CLASSES_ROOT","HKEY_CURRENT_USER","HKEY_USERS"],ans:2,exp:"The HKEY_CURRENT_USER (HKCU) hive contains configuration information tailored explicitly to the user currently logged into the session. It manages individualized settings such as desktop wallpaper, customized environmental variables, application preferences, and mapped network drives."},hi:{q:"विंडोज रजिस्ट्री की जटिल पदानुक्रमित संरचना में, कौन सी प्राथमिक रूट कुंजी (root key hive) भौतिक रूप से लॉग-ऑन उपयोगकर्ता के लिए विशिष्ट डेटा को सुरक्षित रूप से संग्रहीत करती है?",opts:["HKEY_LOCAL_MACHINE","HKEY_CLASSES_ROOT","HKEY_CURRENT_USER","HKEY_USERS"],ans:2,exp:"HKEY_CURRENT_USER (HKCU) हाइव में वर्तमान में सत्र में लॉग इन किए गए उपयोगकर्ता के लिए स्पष्ट रूप से अनुकूलित कॉन्फ़िगरेशन जानकारी होती है। यह डेस्कटॉप वॉलपेपर, कस्टमाइज़्ड एनवायरनमेंटल वेरिएबल्स और एप्लिकेशन प्राथमिकताओं जैसी वैयक्तिकृत सेटिंग्स का प्रबंधन करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which Microsoft Management Console (MMC) snap-in is explicitly utilized to aggressively configure, stop, start, or disable background system processes?",opts:["regedit.exe","msconfig.exe","services.msc","gpedit.msc"],ans:2,exp:"Services.msc is a dedicated MMC snap-in. It provides an administrative GUI to rigorously control the execution of long-running background executables (services). Administrators use it to optimize boot times, disable unnecessary bloatware, or manually restart stalled critical network services."},hi:{q:"बैकग्राउंड सिस्टम प्रक्रियाओं को कॉन्फ़िगर करने, रोकने, शुरू करने या अक्षम करने के लिए स्पष्ट रूप से किस Microsoft प्रबंधन कंसोल (MMC) स्नैप-इन का उपयोग किया जाता है?",opts:["regedit.exe","msconfig.exe","services.msc","gpedit.msc"],ans:2,exp:"Services.msc एक समर्पित MMC स्नैप-इन है। यह लंबे समय तक चलने वाले बैकग्राउंड निष्पादन योग्य (सेवाओं) के निष्पादन को नियंत्रित करने के लिए एक प्रशासनिक GUI प्रदान करता है। प्रशासक इसका उपयोग बूट समय को अनुकूलित करने या अटकी हुई महत्वपूर्ण नेटवर्क सेवाओं को पुनरारंभ करने के लिए करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"The powerful administrative tool accessed via 'gpedit.msc' is strictly known as the:",opts:["Group Policy Editor","Global Performance Editor","GUI Partition Editor","General Profile Editor"],ans:0,exp:"The Local Group Policy Editor (gpedit.msc) is an advanced, immensely powerful administrative tool. It allows deep manipulation of Windows behavior, enforcing rigid policies regarding user rights, software restrictions, password complexity, and detailed security configurations bypassing standard UI limits."},hi:{q:"'gpedit.msc' के माध्यम से एक्सेस किए गए शक्तिशाली प्रशासनिक टूल को सख्ती से किस रूप में जाना जाता है?",opts:["ग्रुप पॉलिसी एडिटर (Group Policy Editor)","ग्लोबल परफॉरमेंस एडिटर","GUI पार्टीशन एडिटर","जनरल प्रोफाइल एडिटर"],ans:0,exp:"स्थानीय समूह नीति संपादक (Local Group Policy Editor - gpedit.msc) एक उन्नत, बेहद शक्तिशाली प्रशासनिक उपकरण है। यह उपयोगकर्ता के अधिकारों, सॉफ़्टवेयर प्रतिबंधों और विस्तृत सुरक्षा कॉन्फ़िगरेशन के संबंध में कठोर नीतियों को लागू करते हुए, विंडोज व्यवहार में गहरे हेरफेर की अनुमति देता है।"}},
{type:"mcq",diff:"hard",en:{q:"If a system administrator needs to meticulously audit system crashes, application faults, or security logons, which utility should they access?",opts:["Event Viewer","Device Manager","Disk Management","Task Scheduler"],ans:0,exp:"The Event Viewer is a complex administrative utility that logs critical system activities. It acts as a forensic journal, categorizing background events into Error, Warning, or Information logs. It is essential for deeply diagnosing silent application crashes or auditing failed security logins."},hi:{q:"यदि किसी सिस्टम प्रशासक को सिस्टम क्रैश, एप्लिकेशन दोष या सुरक्षा लॉगऑन का सावधानीपूर्वक ऑडिट करने की आवश्यकता है, तो उन्हें किस उपयोगिता तक पहुंचना चाहिए?",opts:["इवेंट व्यूअर (Event Viewer)","डिवाइस मैनेजर","डिस्क मैनेजमेंट","टास्क शेड्यूलर"],ans:0,exp:"इवेंट व्यूअर एक जटिल प्रशासनिक उपयोगिता है जो महत्वपूर्ण सिस्टम गतिविधियों को लॉग करता है। यह बैकग्राउंड इवेंट्स को एरर, वॉर्निंग या इंफॉर्मेशन लॉग्स में वर्गीकृत करता है। साइलेंट एप्लिकेशन क्रैश का गहराई से निदान करने के लिए यह आवश्यक है।"}},
{type:"mcq",diff:"hard",en:{q:"In standard Windows architecture, what specific purpose does the heavily protected 'pagefile.sys' file serve?",opts:["It stores the Master Boot Record","It acts as the dedicated backing store for Virtual Memory (RAM extension)","It logs critical kernel crash dumps natively","It archives previous versions of the Registry"],ans:1,exp:"The 'pagefile.sys' is a hidden system file physically located on the root of the system drive. It functions strictly as the backing store for Windows Virtual Memory. When physical RAM is exhausted, inactive memory blocks are systematically swapped into this file to prevent system crashes."},hi:{q:"मानक विंडोज वास्तुकला में, भारी संरक्षित 'pagefile.sys' फ़ाइल किस विशिष्ट उद्देश्य की पूर्ति करती है?",opts:["यह मास्टर बूट रिकॉर्ड को स्टोर करता है","यह वर्चुअल मेमोरी (RAM एक्सटेंशन) के लिए समर्पित बैकिंग स्टोर के रूप में कार्य करता है","यह महत्वपूर्ण कर्नेल क्रैश डंप को मूल रूप से लॉग करता है","यह रजिस्ट्री के पिछले संस्करणों को संग्रहीत करता है"],ans:1,exp:"'pagefile.sys' सिस्टम ड्राइव की जड़ पर भौतिक रूप से स्थित एक छिपी हुई सिस्टम फ़ाइल है। यह विंडोज वर्चुअल मेमोरी के लिए बैकिंग स्टोर के रूप में सख्ती से काम करता है। जब भौतिक रैम समाप्त हो जाती है, तो सिस्टम क्रैश को रोकने के लिए मेमोरी ब्लॉक को व्यवस्थित रूप से इस फ़ाइल में बदल दिया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"The critical 'System32' directory, containing vital core DLLs and executables, is inherently located inside which parent folder?",opts:["C:\\Program Files","C:\\Users","C:\\Windows","C:\\Boot"],ans:2,exp:"The System32 folder (C:\\Windows\\System32) is the most critical directory in the Windows NT architecture. It houses the absolute core operating system files, critical hardware drivers, essential Control Panel applets (.cpl), and vital Dynamic Link Libraries (.dll) required for system functionality."},hi:{q:"महत्वपूर्ण कोर DLL और निष्पादन योग्य (executables) युक्त महत्वपूर्ण 'System32' निर्देशिका मुख्य रूप से किस मूल फ़ोल्डर के अंदर स्थित है?",opts:["C:\\Program Files","C:\\Users","C:\\Windows","C:\\Boot"],ans:2,exp:"System32 फ़ोल्डर (C:\\Windows\\System32) विंडोज NT आर्किटेक्चर में सबसे महत्वपूर्ण निर्देशिका है। इसमें मुख्य ऑपरेटिंग सिस्टम फ़ाइलें, महत्वपूर्ण हार्डवेयर ड्राइवर, आवश्यक कंट्रोल पैनल एप्लेट (.cpl), और सिस्टम कार्यक्षमता के लिए आवश्यक डायनेमिक लिंक लाइब्रेरी (.dll) मौजूद हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Which powerful command-line utility strictly scans the integrity of all protected system files and replaces incorrect versions with Microsoft originals?",opts:["CHKDSK /F","SFC /SCANNOW","DISM /Online","FORMAT C:"],ans:1,exp:"The System File Checker (sfc.exe) invoked with the '/scannow' flag is a critical forensic tool. It thoroughly scans all mathematically verified core Windows files. If it detects corruption or unauthorized modifications by malware, it replaces the damaged files directly from the cached DLL cache."},hi:{q:"कौन सी शक्तिशाली कमांड-लाइन उपयोगिता सभी संरक्षित सिस्टम फ़ाइलों की अखंडता को सख्ती से स्कैन करती है और गलत संस्करणों को Microsoft के मूल (originals) से बदल देती है?",opts:["CHKDSK /F","SFC /SCANNOW","DISM /Online","FORMAT C:"],ans:1,exp:"सिस्टम फ़ाइल चेकर (sfc.exe) '/scannow' फ़्लैग के साथ लागू किया गया एक महत्वपूर्ण उपकरण है। यह सभी मुख्य विंडोज फ़ाइलों को स्कैन करता है। यदि यह मैलवेयर द्वारा भ्रष्टाचार या अनधिकृत संशोधनों का पता लगाता है, तो यह क्षतिग्रस्त फ़ाइलों को सीधे कैश्ड DLL कैश से बदल देता है।"}},
{type:"mcq",diff:"hard",en:{q:"When utilizing the Check Disk utility via CLI, what does the specific syntax parameter '/f' accomplish?",opts:["Finds bad hardware sectors","Fixes logical file system errors on the disk","Formats the disk entirely","Forces a hard unmount of the volume"],ans:1,exp:"Executing 'chkdsk /f' commands the utility to not merely scan, but actively attempt to Fix logical file system errors it encounters on the target disk. It repairs issues like cross-linked files or orphaned clusters. Finding physical bad sectors requires the much slower '/r' parameter."},hi:{q:"CLI के माध्यम से चेक डिस्क (Check Disk) उपयोगिता का उपयोग करते समय, विशिष्ट सिंटैक्स पैरामीटर '/f' क्या पूरा करता है?",opts:["खराब हार्डवेयर क्षेत्रों (sectors) का पता लगाता है","डिस्क पर तार्किक फ़ाइल सिस्टम त्रुटियों को ठीक करता है (Fixes errors)","डिस्क को पूरी तरह से स्वरूपित करता है","वॉल्यूम को हार्ड अनमाउंट करने के लिए बाध्य करता है"],ans:1,exp:"'chkdsk /f' निष्पादित करने से उपयोगिता को केवल स्कैन करने का ही नहीं, बल्कि लक्ष्य डिस्क पर होने वाली तार्किक फ़ाइल सिस्टम त्रुटियों को सक्रिय रूप से ठीक (Fix) करने का आदेश मिलता है। भौतिक खराब क्षेत्रों को खोजने के लिए बहुत धीमे '/r' पैरामीटर की आवश्यकता होती है।"}},
{type:"mcq",diff:"hard",en:{q:"Within a user's profile directory (C:\\Users\\Name), what is the specific function of the naturally hidden 'AppData' folder?",opts:["To store the user's personal downloaded media","To store software application settings, cache, and profile configurations specific to that user","To archive deleted files bypassing the Recycle Bin","To store global system-wide hardware drivers"],ans:1,exp:"The AppData (Application Data) folder is deliberately hidden. It serves as the dedicated repository for software programs to store user-specific customized settings, temporary cache files, saved game states, and web browser profiles without cluttering the visible Documents folder."},hi:{q:"किसी उपयोगकर्ता की प्रोफ़ाइल निर्देशिका (C:\\Users\\Name) के भीतर, स्वाभाविक रूप से छिपे हुए 'AppData' फ़ोल्डर का विशिष्ट कार्य क्या है?",opts:["उपयोगकर्ता के व्यक्तिगत डाउनलोड किए गए मीडिया को संग्रहीत करने के लिए","उस उपयोगकर्ता के लिए विशिष्ट सॉफ़्टवेयर एप्लिकेशन सेटिंग्स, कैश और प्रोफ़ाइल कॉन्फ़िगरेशन को संग्रहीत करने के लिए","रिसाइकिल बिन को दरकिनार कर हटाई गई फ़ाइलों को संग्रहीत करने के लिए","वैश्विक सिस्टम-व्यापी हार्डवेयर ड्राइवरों को संग्रहीत करने के लिए"],ans:1,exp:"AppData (एप्लिकेशन डेटा) फ़ोल्डर जानबूझकर छिपा हुआ है। यह सॉफ्टवेयर प्रोग्रामों के लिए उपयोगकर्ता-विशिष्ट अनुकूलित सेटिंग्स, अस्थायी कैश फ़ाइलों, सहेजे गए गेम स्टेट्स और वेब ब्राउज़र प्रोफाइल को दृश्यमान दस्तावेज़ फ़ोल्डर को अव्यवस्थित किए बिना संग्रहीत करने के लिए एक समर्पित भंडार है।"}},
{type:"mcq",diff:"hard",en:{q:"What critical function does the 'PATH' System Environment Variable perform when executing commands?",opts:["It tells the OS exactly where to save downloaded files","It dictates the mathematical directory sequence the OS searches to find executable files typed in the command prompt","It routes incoming network traffic to the correct software port","It strictly limits the physical path length of nested folders to 256 characters"],ans:1,exp:"The PATH environment variable is a vital string of directories. When a user types a command (like 'ping' or 'java') without an absolute path, the OS sequentially searches every directory explicitly listed in the PATH variable to locate the associated executable file."},hi:{q:"कमांड निष्पादित करते समय 'PATH' सिस्टम पर्यावरण चर (System Environment Variable) कौन सा महत्वपूर्ण कार्य करता है?",opts:["यह OS को बताता है कि डाउनलोड की गई फ़ाइलों को कहाँ सहेजना है","यह कमांड प्रॉम्प्ट में टाइप की गई निष्पादन योग्य फ़ाइलों को खोजने के लिए OS द्वारा खोजी जाने वाली निर्देशिका अनुक्रम को निर्देशित करता है","यह आने वाले नेटवर्क ट्रैफ़िक को सही सॉफ़्टवेयर पोर्ट पर रूट करता है","यह नेस्टेड फ़ोल्डरों की भौतिक पथ लंबाई को 256 वर्णों तक सीमित करता है"],ans:1,exp:"PATH पर्यावरण चर निर्देशिकाओं की एक महत्वपूर्ण स्ट्रिंग है। जब कोई उपयोगकर्ता पूर्ण पथ के बिना कोई कमांड (जैसे 'ping') टाइप करता है, तो OS संबंधित निष्पादन योग्य फ़ाइल का पता लगाने के लिए PATH चर में स्पष्ट रूप से सूचीबद्ध प्रत्येक निर्देशिका को क्रमिक रूप से खोजता है।"}},
{type:"mcq",diff:"hard",en:{q:"In Windows networking nomenclature, what does a UNC path structurally look like?",opts:["C:\\SharedFolder\\file.txt","//server/sharedfolder/file.txt","\\\\ServerName\\SharedFolder\\file.txt","http://ServerName/SharedFolder/"],ans:2,exp:"UNC stands for Universal Naming Convention. It is a strictly standardized syntax used in Windows to specify the location of resources on a local area network (LAN) bypassing drive letters. The exact rigid format requires a double backslash prefix: \\\\HostName\\ShareName\\Path."},hi:{q:"विंडोज नेटवर्किंग नामकरण में, एक UNC पथ संरचनात्मक रूप से कैसा दिखता है?",opts:["C:\\SharedFolder\\file.txt","//server/sharedfolder/file.txt","\\\\ServerName\\SharedFolder\\file.txt","http://ServerName/SharedFolder/"],ans:2,exp:"UNC का अर्थ यूनिवर्सल नेमिंग कन्वेंशन है। यह ड्राइव अक्षरों को दरकिनार करते हुए लोकल एरिया नेटवर्क (LAN) पर संसाधनों का स्थान निर्दिष्ट करने के लिए विंडोज में उपयोग किया जाने वाला एक कड़ाई से मानकीकृत सिंटैक्स है। सटीक कठोर प्रारूप के लिए दोहरे बैकस्लैश (\\\\) उपसर्ग की आवश्यकता होती है।"}},
{type:"mcq",diff:"hard",en:{q:"Files ending in the extension '.bat' are heavily utilized for what specific advanced administrative purpose?",opts:["Installing complex GUI themes","Automating sequences of command-line operations via batch processing","Compressing large video files","Encrypting sensitive system databases"],ans:1,exp:"A .bat (Batch) file is a raw text file containing a sequential list of CLI commands. When executed, the Windows Command Processor (cmd.exe) reads the file line-by-line, automating repetitive administrative tasks, environment setup, or complex deployment scripts without manual human intervention."},hi:{q:"एक्सटेंशन '.bat' के साथ समाप्त होने वाली फ़ाइलों का उपयोग किस विशिष्ट उन्नत प्रशासनिक उद्देश्य के लिए भारी मात्रा में किया जाता है?",opts:["जटिल GUI थीम स्थापित करना","बैच प्रोसेसिंग के माध्यम से कमांड-लाइन संचालन के अनुक्रमों को स्वचालित करना","बड़ी वीडियो फ़ाइलों को संपीड़ित करना","संवेदनशील सिस्टम डेटाबेस को एन्क्रिप्ट करना"],ans:1,exp:"एक .bat (बैच) फ़ाइल एक कच्ची पाठ फ़ाइल है जिसमें CLI कमांड की एक अनुक्रमिक सूची होती है। निष्पादित होने पर, विंडोज कमांड प्रोसेसर (cmd.exe) फ़ाइल को लाइन-दर-लाइन पढ़ता है, मैनुअल मानवीय हस्तक्षेप के बिना दोहराए जाने वाले प्रशासनिक कार्यों को स्वचालित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which sophisticated Windows component permits administrators to trigger specific scripts or programs to execute automatically at mathematically predetermined times or specific system events?",opts:["Task Scheduler","Resource Monitor","Services.msc","Event Viewer"],ans:0,exp:"The Task Scheduler is a robust automation service natively integrated into Windows. Administrators leverage it to strictly schedule routine maintenance, backup scripts, or software updates based on specific triggers (e.g., exact time, user logon, or a specific Event ID occurring in the Event Log)."},hi:{q:"कौन सा परिष्कृत विंडोज घटक प्रशासकों को विशिष्ट स्क्रिप्ट या प्रोग्राम को गणितीय रूप से पूर्व निर्धारित समय या विशिष्ट सिस्टम ईवेंट पर स्वचालित रूप से निष्पादित करने के लिए ट्रिगर करने की अनुमति देता है?",opts:["टास्क शेड्यूलर (Task Scheduler)","रिसोर्स मॉनिटर","Services.msc","इवेंट व्यूअर"],ans:0,exp:"टास्क शेड्यूलर विंडोज़ में मूल रूप से एकीकृत एक मजबूत स्वचालन सेवा है। प्रशासक विशिष्ट ट्रिगर्स (जैसे, सटीक समय, उपयोगकर्ता लॉगऑन, या ईवेंट लॉग में होने वाली विशिष्ट ईवेंट आईडी) के आधार पर नियमित रखरखाव, बैकअप स्क्रिप्ट या सॉफ़्टवेयर अपडेट को सख्ती से शेड्यूल करने के लिए इसका लाभ उठाते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What specifically triggers a BSOD (Blue Screen of Death) in the Windows operating system architecture?",opts:["A failure of an application like Microsoft Word","A catastrophic hardware failure or a critical system-level driver crashing the NT Kernel","A temporary loss of internet connectivity","The hard drive reaching maximum storage capacity"],ans:1,exp:"A BSOD (Stop Error) occurs uniquely when the core Windows NT kernel encounters an unrecoverable, fatal mathematical or hardware fault. This is typically precipitated by severely corrupted low-level hardware drivers, faulty RAM, or catastrophic physical hardware failure that compromises kernel security."},hi:{q:"विंडोज ऑपरेटिंग सिस्टम आर्किटेक्चर में BSOD (ब्लू स्क्रीन ऑफ डेथ) विशेष रूप से क्या ट्रिगर करता है?",opts:["Microsoft Word जैसे एप्लिकेशन की विफलता","एक विनाशकारी हार्डवेयर विफलता या NT कर्नेल को क्रैश करने वाला एक महत्वपूर्ण सिस्टम-स्तरीय ड्राइवर","इंटरनेट कनेक्टिविटी का अस्थायी नुकसान","हार्ड ड्राइव का अधिकतम भंडारण क्षमता तक पहुंचना"],ans:1,exp:"BSOD (स्टॉप एरर) विशेष रूप से तब होता है जब कोर विंडोज NT कर्नेल को पुनर्प्राप्त न होने योग्य, घातक गणितीय या हार्डवेयर दोष का सामना करना पड़ता है। यह आमतौर पर गंभीर रूप से दूषित निम्न-स्तरीय हार्डवेयर ड्राइवरों, दोषपूर्ण रैम या विनाशकारी भौतिक हार्डवेयर विफलता के कारण होता है।"}},
{type:"mcq",diff:"hard",en:{q:"When an administrator actively forces Windows to boot into 'Safe Mode', what specific architectural restriction is mathematically applied?",opts:["The OS boots entirely from the network without using the hard drive","The OS strictly loads only the absolute minimum generic drivers and core services required to function","The OS disables the GUI and forces the user into a pure DOS prompt","The OS bypasses all password security protocols"],ans:1,exp:"Safe Mode is a diagnostic startup environment. To brutally isolate the source of system instability, Windows intentionally disables all third-party startup applications, advanced graphics drivers, and non-essential services. It boots using only basic generic VGA drivers and critical core services."},hi:{q:"जब कोई व्यवस्थापक विंडोज को 'सेफ मोड' में बूट करने के लिए सक्रिय रूप से बाध्य करता है, तो कौन सा विशिष्ट वास्तुशिल्प प्रतिबंध गणितीय रूप से लागू होता है?",opts:["OS हार्ड ड्राइव का उपयोग किए बिना पूरी तरह से नेटवर्क से बूट होता है","OS सख्ती से काम करने के लिए आवश्यक केवल न्यूनतम जेनेरिक ड्राइवर और कोर सेवाएं लोड करता है","OS GUI को अक्षम करता है और उपयोगकर्ता को शुद्ध DOS प्रॉम्प्ट में धकेलता है","OS सभी पासवर्ड सुरक्षा प्रोटोकॉल को बायपास करता है"],ans:1,exp:"सेफ मोड एक डायग्नोस्टिक स्टार्टअप वातावरण है। सिस्टम की अस्थिरता के स्रोत को अलग करने के लिए, विंडोज जानबूझकर सभी तृतीय-पक्ष स्टार्टअप एप्लिकेशन, उन्नत ग्राफिक्स ड्राइवरों और गैर-आवश्यक सेवाओं को अक्षम कर देता है। यह केवल बुनियादी जेनेरिक वीजीए ड्राइवरों का उपयोग करके बूट होता है।"}},
{type:"mcq",diff:"hard",en:{q:"The powerful 'msconfig.exe' administrative utility is predominantly utilized to meticulously troubleshoot which specific phase of the operating system?",opts:["The network configuration phase","The startup/boot phase and background services execution","The physical disk formatting phase","The application installation phase"],ans:1,exp:"The System Configuration Utility (msconfig) is designed explicitly to troubleshoot the Windows startup process. Administrators use it to selectively disable rogue startup applications, force Safe Boot parameters, and brutally toggle third-party services to isolate software conflicts causing boot delays."},hi:{q:"शक्तिशाली 'msconfig.exe' प्रशासनिक उपयोगिता का उपयोग मुख्य रूप से ऑपरेटिंग सिस्टम के किस विशिष्ट चरण का सावधानीपूर्वक निवारण करने के लिए किया जाता है?",opts:["नेटवर्क कॉन्फ़िगरेशन चरण","स्टार्टअप/बूट चरण और पृष्ठभूमि सेवा निष्पादन (startup/boot phase)","भौतिक डिस्क स्वरूपण चरण","एप्लिकेशन स्थापना चरण"],ans:1,exp:"सिस्टम कॉन्फ़िगरेशन उपयोगिता (msconfig) को विशेष रूप से विंडोज स्टार्टअप प्रक्रिया के निवारण के लिए डिज़ाइन किया गया है। प्रशासक इसका उपयोग स्टार्टअप एप्लिकेशन को चुनिंदा रूप से अक्षम करने, सेफ बूट मापदंडों को मजबूर करने और बूट देरी पैदा करने वाले सॉफ़्टवेयर संघर्षों को अलग करने के लिए करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Executing 'regedit' in the Run dialog directly launches the Registry Editor. What fundamental underlying data structure does the Registry utilize?",opts:["A flat-file CSV database","A hierarchical tree structure of Keys and Values","A relational SQL database","A sequential linked-list"],ans:1,exp:"The Windows Registry is a massive, highly complex central repository. Architecturally, it abandons flat files in favor of a rigid hierarchical tree structure composed of 'Keys' (acting like logical folders) and 'Values' (the actual mathematical data/settings configuring the OS and apps)."},hi:{q:"रन डायलॉग में 'regedit' निष्पादित करने से सीधे रजिस्ट्री संपादक लॉन्च होता है। रजिस्ट्री किस मूलभूत अंतर्निहित डेटा संरचना का उपयोग करती है?",opts:["एक फ्लैट-फाइल CSV डेटाबेस","कुंजियों और मानों की एक पदानुक्रमित ट्री संरचना (hierarchical tree structure)","एक रिलेशनल SQL डेटाबेस","एक अनुक्रमिक लिंक-सूची"],ans:1,exp:"विंडोज रजिस्ट्री एक विशाल, अत्यधिक जटिल केंद्रीय भंडार है। वास्तुशिल्प रूप से, यह एक कठोर पदानुक्रमित ट्री संरचना के पक्ष में फ्लैट फाइलों को छोड़ देता है जो 'कुंजियों' (तार्किक फ़ोल्डरों की तरह काम कर रहे हैं) और 'मूल्यों' (वास्तविक डेटा/सेटिंग्स) से बना है।"}},
{type:"mcq",diff:"hard",en:{q:"In advanced NTFS file security, if a user belongs to a Group granted 'Modify' permission, but their individual user account is explicitly set to 'Deny' Write permission, what is the mathematical outcome?",opts:["The user can write because Group permissions override individual permissions","The user is strictly denied Write access because explicit Deny permissions always take absolute precedence","The system crashes due to permission conflict","The user receives a temporary 10-minute Write access token"],ans:1,exp:"Windows NTFS permission logic adheres to a rigid mathematical hierarchy. The paramount rule is that an explicit 'Deny' permission assigned anywhere mathematically overrides any and all 'Allow' permissions inherited from parent folders or security groups, ensuring absolute access restriction."},hi:{q:"उन्नत NTFS फ़ाइल सुरक्षा में, यदि कोई उपयोगकर्ता 'संशोधित करें' (Modify) अनुमति वाले समूह से संबंधित है, लेकिन उनका व्यक्तिगत उपयोगकर्ता खाता स्पष्ट रूप से 'लिखने से इनकार करें' (Deny Write) पर सेट है, तो इसका गणितीय परिणाम क्या है?",opts:["उपयोगकर्ता लिख ​​सकता है क्योंकि समूह अनुमतियां व्यक्तिगत अनुमतियों को ओवरराइड करती हैं","उपयोगकर्ता को कड़ाई से लिखने (Write) की पहुंच से वंचित किया जाता है क्योंकि स्पष्ट अस्वीकार (Deny) अनुमतियां हमेशा पूर्ण प्राथमिकता लेती हैं","अनुमति संघर्ष के कारण सिस्टम क्रैश हो जाता है","उपयोगकर्ता को एक अस्थायी 10-मिनट का राइट एक्सेस टोकन प्राप्त होता है"],ans:1,exp:"विंडोज NTFS अनुमति तर्क एक कठोर गणितीय पदानुक्रम का पालन करता है। सर्वोपरि नियम यह है कि कहीं भी निर्दिष्ट एक स्पष्ट 'इनकार' (Deny) अनुमति गणितीय रूप से पैरेंट फ़ोल्डरों या सुरक्षा समूहों से विरासत में मिली किसी भी और सभी 'अनुमति' (Allow) को ओवरराइड करती है।"}},
{type:"mcq",diff:"hard",en:{q:"What advanced NTFS feature operates in the background utilizing the Volume Shadow Copy Service to mathematically preserve historical versions of modified files?",opts:["System File Checker","Previous Versions (Shadow Copies)","Disk Quotas","NTFS Compression"],ans:1,exp:"The Volume Shadow Copy Service (VSS) is a complex framework that actively takes block-level mathematical snapshots of the NTFS volume. This powers the 'Previous Versions' feature, allowing users to seamlessly right-click a deeply corrupted document and revert it to an exact historical state."},hi:{q:"संशोधित फ़ाइलों के ऐतिहासिक संस्करणों को गणितीय रूप से संरक्षित करने के लिए वॉल्यूम शैडो कॉपी सर्विस का उपयोग करके पृष्ठभूमि में कौन सी उन्नत NTFS सुविधा संचालित होती है?",opts:["सिस्टम फ़ाइल चेकर","पिछले संस्करण (Shadow Copies - शैडो कॉपी)","डिस्क कोटा","NTFS संपीड़न (Compression)"],ans:1,exp:"वॉल्यूम शैडो कॉपी सर्विस (VSS) एक जटिल ढांचा है जो सक्रिय रूप से NTFS वॉल्यूम के ब्लॉक-स्तरीय स्नैपशॉट लेता है। यह 'पिछले संस्करण' (Previous Versions) सुविधा को शक्ति प्रदान करता है, जिससे उपयोगकर्ता गहराई से भ्रष्ट दस्तावेज़ पर राइट-क्लिक कर सकते हैं और इसे ऐतिहासिक स्थिति में वापस ला सकते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"What specifically is Windows PE (Preinstallation Environment)?",opts:["A graphical design software suite","A highly stripped-down, lightweight version of Windows deployed strictly for troubleshooting, capturing, and applying disk images","A premium enterprise version of Windows 11","A virtualization software like VMware"],ans:1,exp:"Windows PE is a tiny, purpose-built, bare-bones operating system running entirely in RAM. IT professionals rely on it strictly to boot bare-metal PCs over a network or USB drive to deploy massive OS images, run rigorous offline malware scans, or mathematically recover a broken OS."},hi:{q:"विंडोज PE (प्रीइंस्टॉलेशन एनवायरनमेंट) विशेष रूप से क्या है?",opts:["एक ग्राफिकल डिजाइन सॉफ्टवेयर सूट","विंडोज का एक अत्यधिक छोटा, हल्का संस्करण जिसे कड़ाई से समस्या निवारण, डिस्क छवियों को कैप्चर करने और लागू करने के लिए तैनात किया गया है","विंडोज 11 का एक प्रीमियम एंटरप्राइज संस्करण","VMware की तरह एक वर्चुअलाइजेशन सॉफ्टवेयर"],ans:1,exp:"विंडोज पीई एक छोटा, उद्देश्य-निर्मित ऑपरेटिंग सिस्टम है जो पूरी तरह से रैम में चलता है। आईटी पेशेवर नेटवर्क या यूएसबी ड्राइव पर बेयर-मेटल पीसी को बूट करने, बड़े पैमाने पर ओएस छवियों को तैनात करने, या एक टूटे हुए ओएस को पुनर्प्राप्त करने के लिए कड़ाई से इस पर भरोसा करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Before digitally capturing a massive Windows image for enterprise cloning, which mandatory mathematical tool strips the specific SID (Security Identifier) to generalize the installation?",opts:["DISM","Sysprep (System Preparation Tool)","DiskPart","ImageX"],ans:1,exp:"Sysprep is heavily utilized in enterprise deployments. Mathematically cloning a hard drive exactly copies its unique Security Identifier (SID). If two identical computers with the exact same SID join an Active Directory domain, catastrophic network collision occurs. Sysprep brutally strips this SID to 'generalize' the image."},hi:{q:"एंटरप्राइज़ क्लोनिंग के लिए बड़े पैमाने पर विंडोज छवि को डिजिटल रूप से कैप्चर करने से पहले, कौन सा अनिवार्य गणितीय उपकरण स्थापना को सामान्य (generalize) बनाने के लिए विशिष्ट SID (सुरक्षा पहचानकर्ता) को हटा देता है?",opts:["DISM","Sysprep (सिस्टम प्रेपरेशन टूल)","DiskPart","ImageX"],ans:1,exp:"Sysprep का बड़े पैमाने पर उद्यम परिनियोजन (enterprise deployments) में उपयोग किया जाता है। हार्ड ड्राइव की क्लोनिंग इसकी अनूठी सुरक्षा पहचानकर्ता (SID) की प्रतिलिपि बनाती है। यदि एक ही SID वाले दो कंप्यूटर डोमेन में शामिल होते हैं, तो नेटवर्क टकराव होता है। Sysprep इस SID को हटा देता है।"}},
{type:"mcq",diff:"hard",en:{q:"In older BIOS-based architecture, the Master Boot Record (MBR) rigidly resides exactly at which mathematical physical location on a hard drive?",opts:["The very last sector of the disk","The geometric center of the primary platter","Absolute physical Sector 0 (CHS 0,0,1)","Inside the C:\\Windows directory"],ans:2,exp:"The Master Boot Record is structurally tiny (exactly 512 bytes) but fundamentally critical. It is mathematically hardcoded to exist at the absolute very first physical sector of the hard drive (Sector 0). The BIOS blindly loads this exact sector into memory to trigger the bootstrap process."},hi:{q:"पुरानी BIOS-आधारित वास्तुकला में, मास्टर बूट रिकॉर्ड (MBR) हार्ड ड्राइव पर किस गणितीय भौतिक स्थान पर कठोरता से स्थित होता है?",opts:["डिस्क का बिल्कुल अंतिम क्षेत्र (sector)","प्राथमिक थाली का ज्यामितीय केंद्र","निरपेक्ष भौतिक क्षेत्र 0 (Absolute physical Sector 0 / CHS 0,0,1)","C:\\Windows निर्देशिका के अंदर"],ans:2,exp:"मास्टर बूट रिकॉर्ड संरचनात्मक रूप से छोटा (ठीक 512 बाइट्स) है लेकिन मूल रूप से महत्वपूर्ण है। यह हार्ड ड्राइव (सेक्टर 0) के पहले भौतिक क्षेत्र में मौजूद होने के लिए गणितीय रूप से हार्डकोडेड है। BIOS बूटस्ट्रैप प्रक्रिया को ट्रिगर करने के लिए इस सटीक क्षेत्र को मेमोरी में लोड करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Due to absolute mathematical addressing limits, an MBR formatted hard disk intrinsically cannot support total partitions physically larger than:",opts:["2 Terabytes (TB)","4 Gigabytes (GB)","128 Exabytes (EB)","1 Petabyte (PB)"],ans:0,exp:"The classic Master Boot Record (MBR) architecture relies on archaic 32-bit mathematical addressing for its logical block addressing (LBA). This strictly caps the maximum addressable physical storage partition size to exactly 2 Terabytes. Drives larger than 2TB absolutely require the modern GPT standard."},hi:{q:"पूर्ण गणितीय एड्रेसिंग सीमाओं के कारण, एक MBR स्वरूपित हार्ड डिस्क आंतरिक रूप से कितने आकार से बड़े कुल विभाजनों का समर्थन नहीं कर सकती है?",opts:["2 टेराबाइट्स (TB)","4 गीगाबाइट्स (GB)","128 एक्साबाइट्स (EB)","1 पेटाबाइट (PB)"],ans:0,exp:"क्लासिक मास्टर बूट रिकॉर्ड (MBR) वास्तुकला इसके तार्किक ब्लॉक एड्रेसिंग (LBA) के लिए पुराने 32-बिट गणितीय एड्रेसिंग पर निर्भर करती है। यह अधिकतम भौतिक भंडारण विभाजन आकार को ठीक 2 टेराबाइट्स तक सीमित करता है। 2TB से बड़े ड्राइव के लिए आधुनिक GPT मानक की आवश्यकता होती है।"}},
{type:"mcq",diff:"hard",en:{q:"What specifically does the abbreviation DLL mathematically represent in the Windows NT framework?",opts:["Data Linked List","Dynamic Link Library","Direct Linear Logic","Digital Low Level"],ans:1,exp:"A Dynamic Link Library (.dll) is a sophisticated Microsoft concept. Instead of heavily bloating every individual .exe file with repetitive code, common mathematical functions (like rendering a dialog box) are compiled into standalone DLL files. Multiple programs dynamically share these libraries simultaneously, drastically conserving RAM."},hi:{q:"विंडोज NT फ्रेमवर्क में संक्षिप्त नाम DLL गणितीय रूप से क्या दर्शाता है?",opts:["डेटा लिंक्ड लिस्ट","डायनेमिक लिंक लाइब्रेरी (Dynamic Link Library)","डायरेक्ट लीनियर लॉजिक","डिजिटल लो लेवल"],ans:1,exp:"डायनेमिक लिंक लाइब्रेरी (.dll) एक परिष्कृत माइक्रोसॉफ्ट अवधारणा है। हर अलग .exe फ़ाइल में दोहराए जाने वाले कोड डालने के बजाय, सामान्य गणितीय कार्यों को स्टैंडअलोन DLL फ़ाइलों में संकलित किया जाता है। एकाधिक प्रोग्राम इन पुस्तकालयों को एक साथ साझा करते हैं, जिससे RAM की बचत होती है।"}},
{type:"mcq",diff:"hard",en:{q:"In OS architecture, what highly specialized underlying mathematical layer deliberately isolates the core Windows NT kernel from directly interacting with raw physical hardware?",opts:["The GUI shell","The Command Prompt CLI","The Hardware Abstraction Layer (HAL)","The Master Boot Record"],ans:2,exp:"The Hardware Abstraction Layer (HAL) is an incredibly crucial mathematical layer in Windows. It acts as a universal software bridge. The kernel communicates exclusively with the standardized HAL, and the HAL mathematically translates these requests into the specific proprietary language required by the disparate physical hardware components."},hi:{q:"OS वास्तुकला में, कौन सी अत्यधिक विशिष्ट अंतर्निहित गणितीय परत जानबूझकर मुख्य विंडोज NT कर्नेल को सीधे कच्चे भौतिक हार्डवेयर के साथ बातचीत करने से अलग करती है?",opts:["GUI शेल","कमांड प्रॉम्प्ट CLI","हार्डवेयर एब्स्ट्रैक्शन लेयर (Hardware Abstraction Layer - HAL)","मास्टर बूट रिकॉर्ड"],ans:2,exp:"हार्डवेयर एब्स्ट्रैक्शन लेयर (HAL) विंडोज़ में एक अत्यंत महत्वपूर्ण गणितीय परत है। यह एक सार्वभौमिक सॉफ्टवेयर ब्रिज के रूप में कार्य करता है। कर्नेल विशेष रूप से मानकीकृत HAL के साथ संचार करता है, और HAL इन अनुरोधों को भौतिक हार्डवेयर घटकों द्वारा आवश्यक विशिष्ट भाषा में अनुवादित करता है।"}},
{type:"mcq",diff:"hard",en:{q:"When physical RAM is completely exhausted, the OS aggressively moves deeply inactive 4KB mathematical blocks of memory to the hard drive. What is this strict process called?",opts:["Paging (Swapping)","Defragmentation","Formatting","Hibernating"],ans:0,exp:"Paging (or Swapping) is a fundamental mathematical function of Virtual Memory. When high-speed RAM is full, the OS memory manager aggressively identifies inactive 4KB 'pages' of data and physically writes them down to the sluggish hard drive (Pagefile), freeing up critical RAM for active threads."},hi:{q:"जब भौतिक रैम (RAM) पूरी तरह से समाप्त हो जाती है, तो OS आक्रामक रूप से मेमोरी के निष्क्रिय 4KB गणितीय ब्लॉकों को हार्ड ड्राइव में ले जाता है। इस सख्त प्रक्रिया को क्या कहा जाता है?",opts:["पेजिंग (स्वैपिंग - Paging/Swapping)","डीफ़्रेग्मेंटेशन","फ़ॉर्मेटिंग","हाइबरनेटिंग"],ans:0,exp:"पेजिंग (या स्वैपिंग) वर्चुअल मेमोरी का एक मूलभूत कार्य है। जब उच्च गति वाला रैम भर जाता है, तो ओएस मेमोरी मैनेजर आक्रामक रूप से डेटा के निष्क्रिय 4KB 'पेज' की पहचान करता है और सक्रिय थ्रेड्स के लिए महत्वपूर्ण रैम को खाली करते हुए उन्हें हार्ड ड्राइव (पेजफाइल) में भौतिक रूप से लिखता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which highly specific command-line tool physically manipulates mathematical disk partitions, volumes, and virtual hard disks without the restrictions of the GUI Disk Management snap-in?",opts:["Format","DiskPart","Chkdsk","Robocopy"],ans:1,exp:"DiskPart is an extremely powerful, text-mode command interpreter. While the GUI Disk Management snap-in restricts administrators from brutally wiping active partitions or OEM recovery drives to prevent accidental damage, DiskPart blindly executes these mathematical commands, giving complete, unrestricted administrative control over physical drive sectors."},hi:{q:"कौन सा अत्यधिक विशिष्ट कमांड-लाइन टूल GUI डिस्क प्रबंधन के प्रतिबंधों के बिना गणितीय डिस्क विभाजन, वॉल्यूम और वर्चुअल हार्ड डिस्क में भौतिक रूप से हेरफेर करता है?",opts:["Format","DiskPart (डिस्कपार्ट)","Chkdsk","Robocopy"],ans:1,exp:"DiskPart एक अत्यंत शक्तिशाली, टेक्स्ट-मोड कमांड इंटरप्रेटर है। जबकि GUI डिस्क प्रबंधन स्नैप-इन प्रशासकों को आकस्मिक क्षति को रोकने के लिए सक्रिय विभाजन को पोंछने से रोकता है, DiskPart इन गणितीय कमांडों को आँख बंद करके निष्पादित करता है, जिससे ड्राइव पर पूर्ण नियंत्रण मिलता है।"}},
{type:"tf",diff:"hard",en:{q:"Mathematically changing a file's extension from '.jpg' to '.docx' physically restructures the underlying hexadecimal binary data, converting the image into a valid Word document.",opts:["True","False"],ans:1,exp:"This is entirely false. An extension is merely a mathematical label telling the OS which program to execute. Changing '.jpg' to '.docx' does absolutely nothing to the underlying raw hexadecimal binary data. Word will crash trying to interpret the raw image bits as text formatting data."},hi:{q:"गणितीय रूप से किसी फ़ाइल के एक्सटेंशन को '.jpg' से '.docx' में बदलने से अंतर्निहित हेक्साडेसिमल बाइनरी डेटा शारीरिक रूप से पुनर्गठित हो जाता है, जिससे छवि एक वैध Word दस्तावेज़ में परिवर्तित हो जाती है।",opts:["सही","गलत"],ans:1,exp:"यह पूरी तरह से गलत है। एक एक्सटेंशन केवल एक गणितीय लेबल है जो OS को बताता है कि कौन सा प्रोग्राम निष्पादित करना है। '.jpg' को '.docx' में बदलने से अंतर्निहित कच्चे हेक्साडेसिमल बाइनरी डेटा पर कोई प्रभाव नहीं पड़ता है। वर्ड कच्चे छवि बिट्स को पाठ के रूप में व्याख्या करने की कोशिश करते हुए क्रैश हो जाएगा।"}},
{type:"tf",diff:"hard",en:{q:"Executing a 'System Restore' physically targets and aggressively deletes all personal mathematical documents, photos, and emails created after the chosen exact Restore Point date.",opts:["True","False"],ans:1,exp:"This is mathematically false. System Restore is architecturally engineered to strictly target critical system files, the Registry, and installed executable software. It explicitly and mathematically bypasses all personal user directories (like Documents, Pictures, Desktop), ensuring user-generated data is never deleted during a system rollback."},hi:{q:"'सिस्टम रिस्टोर' (System Restore) निष्पादित करने से चुने गए सटीक रिस्टोर पॉइंट तिथि के बाद बनाए गए सभी व्यक्तिगत गणितीय दस्तावेज़ों, फ़ोटो और ईमेल को भौतिक रूप से लक्षित किया जाता है और हटा दिया जाता है।",opts:["सही","गलत"],ans:1,exp:"यह गणितीय रूप से गलत है। सिस्टम रिस्टोर को सिस्टम फ़ाइलों, रजिस्ट्री और स्थापित सॉफ़्टवेयर को सख्ती से लक्षित करने के लिए आर्किटेक्चरल रूप से इंजीनियर किया गया है। यह स्पष्ट रूप से सभी व्यक्तिगत उपयोगकर्ता निर्देशिकाओं (जैसे दस्तावेज़, चित्र) को दरकिनार करता है, यह सुनिश्चित करता है कि उपयोगकर्ता डेटा कभी नहीं हटाया जाता है।"}}
];
